import { useState, useEffect, Suspense, lazy } from 'react'

// Lazy Load Settings Panels
const ProfileSettings = lazy(() => import('./settings/ProfileSettings'))
const AppearanceSettings = lazy(() => import('./settings/AppearanceSettings'))
const WallpaperSettings = lazy(() => import('./settings/WallpaperSettings'))
const NotificationsSettings = lazy(() => import('./settings/NotificationsSettings'))

function SettingsModal({ isOpen, onClose }) {
    const [activeTab, setActiveTab] = useState('profile')
    const [searchQuery, setSearchQuery] = useState('')

    // Reset search when closing
    useEffect(() => {
        if (!isOpen) setSearchQuery('')
    }, [isOpen])

    // Listen for open-settings event
    useEffect(() => {
        const handleOpen = (e) => {
            if (e.detail?.tab) setActiveTab(e.detail.tab)
        }
        window.addEventListener('open-settings', handleOpen)
        return () => window.removeEventListener('open-settings', handleOpen)
    }, [])

    if (!isOpen) return null

    const sidebarItems = [
        { id: 'profile', label: 'Profile', icon: '👤', component: ProfileSettings },
        { id: 'appearance', label: 'Appearance', icon: '🎨', component: AppearanceSettings },
        { id: 'wallpaper', label: 'Wallpaper', icon: '🖼️', component: WallpaperSettings },
        { id: 'notifications', label: 'Notifications', icon: '🔔', component: NotificationsSettings },
    ]

    const filteredItems = sidebarItems.filter(item =>
        item.label.toLowerCase().includes(searchQuery.toLowerCase())
    )

    const ActiveComponent = sidebarItems.find(item => item.id === activeTab)?.component || ProfileSettings

    return (
        <div className="modal-overlay" onClick={onClose} style={{ backdropFilter: 'blur(24px)' }}>
            <div
                className="settings-modal-window"
                onClick={e => e.stopPropagation()}
            >
                {/* macOS Window Title Bar */}
                <div className="settings-titlebar">
                    <div style={{ display: 'flex', gap: '8px' }}>
                        <div className="traffic-btn red" onClick={onClose}></div>
                        <div className="traffic-btn yellow"></div>
                        <div className="traffic-btn green"></div>
                    </div>
                    {/* Mobile Close Button (Hidden on Desktop) */}
                    <button
                        className="mobile-close-btn"
                        onClick={onClose}
                        style={{ display: 'none', background: 'var(--surface-hover)', border: 'none', borderRadius: '50%', width: 28, height: 28, color: 'var(--text-secondary)', fontSize: 14, cursor: 'pointer', zIndex: 3 }}
                    >✕</button>
                </div>

                <div style={{ display: 'flex', height: '100%', overflow: 'hidden' }}>
                    {/* Left Sidebar */}
                    <div className="settings-sidebar">
                        <div className="sidebar-search-wrapper">
                            <span className="search-icon">🔍</span>
                            <input
                                type="text"
                                placeholder="Search"
                                className="sidebar-search-input"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>

                        <div className="sidebar-scroll-area">
                            {filteredItems.map(item => (
                                <button
                                    key={item.id}
                                    onClick={() => setActiveTab(item.id)}
                                    className={`settings-sidebar-btn ${activeTab === item.id ? 'active' : ''}`}
                                >
                                    <span className="settings-sidebar-icon">{item.icon}</span>
                                    {item.label}
                                </button>
                            ))}
                            {filteredItems.length === 0 && (
                                <div className="no-results">No results</div>
                            )}
                        </div>
                    </div>

                    {/* Main Content */}
                    <div className="settings-content">
                        <Suspense fallback={<div className="settings-loading">Loading...</div>}>
                            <ActiveComponent />
                        </Suspense>
                    </div>
                </div>
            </div>

            <style>{`
                .settings-modal-window {
                    width: 900px; max-width: 95vw;
                    height: 600px;
                    /* Base Liquid Glass */
                    background: rgba(255,255,255,0.1);
                    backdrop-filter: blur(var(--lg-regular-blur));
                    -webkit-backdrop-filter: blur(var(--lg-regular-blur));
                    border: 1px solid rgba(255,255,255,0.2);
                    border-radius: var(--lg-radius-lg);
                    box-shadow: var(--lg-shadow-modal);
                    display: flex; flex-direction: column;
                    overflow: hidden;
                    animation: settingsSlideUp 0.3s var(--ease-out-expo);
                    will-change: transform, opacity;
                    position: relative;
                }
                
                /* Noise Texture */
                .settings-modal-window::before {
                    content: '';
                    position: absolute;
                    inset: 0;
                    background-image: var(--noise-texture);
                    opacity: 0.5;
                    mix-blend-mode: overlay;
                    pointer-events: none;
                    z-index: 0;
                }

                /* Inner Glow/Rim */
                .settings-modal-window::after {
                    content: '';
                    position: absolute;
                    inset: 0;
                    border-radius: 12px;
                    padding: 1px;
                    background: linear-gradient(180deg, rgba(255,255,255,0.2) 0%, transparent 40%);
                    -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
                    -webkit-mask-composite: xor;
                    mask-composite: exclude;
                    pointer-events: none;
                }

                .settings-titlebar {
                    height: 52px;
                    background: transparent; /* Unified with Sidebar */
                    padding: 0 20px;
                    display: flex; align-items: center;
                    flex-shrink: 0;
                    -webkit-app-region: drag;
                    /* No border bottom for unified look, or very subtle */
                    border-bottom: 1px solid rgba(255,255,255,0.05);
                    z-index: 2;
                }

                .traffic-btn {
                    width: 12px; height: 12px; border-radius: 50%;
                    cursor: pointer; transition: opacity 0.15s;
                    box-shadow: inset 0 0 0 0.5px rgba(0,0,0,0.1);
                }
                .traffic-btn:hover { opacity: 0.8; }
                .traffic-btn.red { background: #ff5f57; }
                .traffic-btn.yellow { background: #febc2e; }
                .traffic-btn.green { background: #28c840; }

                .settings-sidebar {
                    width: 250px;
                    /* Thin Glass Sidebar */
                    background: rgba(255,255,255,0.05); /* Subtle addition to window glass */
                    backdrop-filter: blur(10px); /* Stacked blur */
                    padding: 0 16px 16px 16px;
                    display: flex; flex-direction: column; gap: 10px;
                    flex-shrink: 0;
                    border-right: 1px solid rgba(255,255,255,0.1);
                    z-index: 2;
                }

                .sidebar-search-wrapper {
                   position: relative;
                   margin-bottom: 8px;
                   margin-top: 16px;
                }
                .sidebar-search-input {
                    width: 100%;
                    padding: 8px 10px 8px 32px;
                    border-radius: var(--radius-input);
                    border: var(--border-layer-2);
                    background: var(--glass-layer-2);
                    font-size: 13px;
                    outline: none;
                    color: var(--text-primary);
                    transition: all 0.2s;
                }
                .sidebar-search-input:focus {
                    background: var(--glass-layer-3);
                    border-color: var(--primary-color);
                    box-shadow: 0 0 0 2px rgba(102,126,234,0.15);
                }

                .search-icon {
                    position: absolute; left: 10px; top: 50%; transform: translateY(-50%);
                    font-size: 12px; opacity: 0.5; color: var(--text-secondary);
                }

                .settings-sidebar-btn {
                    display: flex; align-items: center; gap: 10px;
                    padding: 8px 12px; border-radius: var(--radius-button); border: none;
                    background: transparent;
                    color: var(--text-primary);
                    cursor: pointer; font-size: 13px; font-weight: 500;
                    text-align: left; width: 100%;
                    transition: all 0.1s;
                }
                .settings-sidebar-btn:hover {
                    background: var(--glass-layer-2);
                }

                .settings-sidebar-btn.active {
                    background: var(--primary-gradient);
                    color: white;
                    box-shadow: var(--shadow-layer-2);
                }
                
                .settings-sidebar-icon { font-size: 16px; }

                .settings-content {
                    flex: 1; overflow-y: auto; overflow-x: hidden;
                    background: var(--glass-layer-2); /* Distinct Content Pane */
                    border-left: 1px solid rgba(255,255,255,0.1); /* Separator */
                    position: relative;
                    z-index: 2;
                }

                .settings-loading {
                    display: flex; align-items: center; justify-content: center;
                    height: 100%; color: var(--text-secondary);
                }
                
                .no-results {
                    padding: 20px; text-align: center; font-size: 13px; color: var(--text-secondary); opacity: 0.7;
                }

                @keyframes settingsSlideUp {
                    from { opacity: 0; transform: scale(0.95) translateY(10px); }
                    to { opacity: 1; transform: scale(1) translateY(0); }
                }

                /* Mobile Optimizations - iOS Bottom Sheet */
                @media (max-width: 768px) {
                    .settings-modal-window {
                        width: 100vw;
                        max-width: 100vw;
                        height: 90vh; /* Bottom sheet style */
                        border-radius: 24px 24px 0 0; /* Only round top corners */
                        position: absolute;
                        bottom: 0;
                        left: 0;
                        right: 0;
                        animation: sheetSlideUp 0.3s cubic-bezier(0.25, 1, 0.5, 1);
                    }

                    @keyframes sheetSlideUp {
                        from { transform: translateY(100%); opacity: 0; }
                        to { transform: translateY(0); opacity: 1; }
                    }

                    .settings-titlebar {
                        height: auto;
                        padding: 16px;
                        justify-content: flex-end; /* Push close to right if no traffic lights */
                    }
                    
                    /* Apple HIG: Add a grabber handle for bottom sheets */
                    .settings-titlebar::before {
                        content: '';
                        position: absolute;
                        top: 8px;
                        left: 50%;
                        transform: translateX(-50%);
                        width: 36px;
                        height: 5px;
                        background: rgba(255,255,255,0.3);
                        border-radius: 10px;
                    }

                    /* Strip macOS Traffic Lights */
                    .traffic-btn {
                        display: none;
                    }

                    /* Add an explicit close button for mobile */
                    .mobile-close-btn {
                        display: block !important;
                    }

                    .settings-modal-window > div {
                        flex-direction: column;
                    }

                    .settings-sidebar {
                        width: 100%;
                        border-right: none;
                        border-bottom: 1px solid rgba(255,255,255,0.1);
                        padding-bottom: 8px;
                    }

                    .sidebar-scroll-area {
                        display: flex;
                        overflow-x: auto;
                        gap: 8px;
                        padding-bottom: 4px;
                        -webkit-overflow-scrolling: touch;
                    }
                    .sidebar-scroll-area::-webkit-scrollbar {
                        display: none;
                    }

                    .settings-sidebar-btn {
                        white-space: nowrap;
                        width: auto;
                        padding: 6px 12px;
                        border-radius: 20px;
                        background: var(--glass-layer-2);
                    }
                    
                    .settings-sidebar-btn.active {
                        background: var(--primary-color);
                    }

                    .settings-content {
                        border-left: none;
                        padding-bottom: env(safe-area-inset-bottom, 20px);
                    }
                }
            `}</style>
        </div>
    )
}

export default SettingsModal
