import { useState, useEffect, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import { useSpotlight } from '../contexts/SpotlightContext'
import StudentDetailModal from './StudentDetailModal'

// Quick-action pages for navigation
const PAGES = [
    { name: 'Dashboard', path: '/dashboard', icon: '📊', description: 'Overview & analytics' },
    { name: 'Students', path: '/students', icon: '👥', description: 'Student management' },
    { name: 'Formation Groups', path: '/groups', icon: '🏘️', description: 'Group management' },
    { name: 'Weekly Reports', path: '/weekly-reports', icon: '📝', description: 'Submit & view reports' },
    { name: 'Checkpoints', path: '/checkpoints', icon: '🎯', description: 'Discernment checkpoints' },
    { name: 'Reports & Export', path: '/exports', icon: '📤', description: 'Export data as CSV' },
    { name: 'Settings', path: '/settings', icon: '⚙️', description: 'App preferences' },
    { name: 'Admin Panel', path: '/admin', icon: '🔧', description: 'User management' },
    { name: 'Audit Logs', path: '/audit', icon: '📋', description: 'Activity history' },
]

const CATEGORIES = ['All', 'Students', 'Groups', 'Notes', 'Pages']

function SpotlightSearch() {
    const { isOpen, closeSpotlight } = useSpotlight()
    const [query, setQuery] = useState('')
    const [category, setCategory] = useState('All')
    const [results, setResults] = useState({ students: [], groups: [], notes: [], pages: [] })
    const [loading, setLoading] = useState(false)
    const [selectedIndex, setSelectedIndex] = useState(0)
    const [selectedStudent, setSelectedStudent] = useState(null)
    const inputRef = useRef(null)
    const navigate = useNavigate()

    // Auto-focus input when opened
    useEffect(() => {
        if (isOpen) {
            setTimeout(() => inputRef.current?.focus(), 50)
            setQuery('')
            setCategory('All')
            setResults({ students: [], groups: [], notes: [], pages: [] })
            setSelectedIndex(0)
        }
    }, [isOpen])

    // Debounced search
    useEffect(() => {
        if (!query.trim()) {
            setResults({ students: [], groups: [], notes: [], pages: [] })
            return
        }

        // Always search pages locally
        const q = query.toLowerCase()
        const matchedPages = PAGES.filter(p =>
            p.name.toLowerCase().includes(q) || p.description.toLowerCase().includes(q)
        ).map(p => ({ ...p, type: 'page' }))

        // Search backend
        const timer = setTimeout(async () => {
            setLoading(true)
            try {
                const res = await fetch(`/api/data/search?q=${encodeURIComponent(query)}`)
                const data = await res.json()
                if (data.success) {
                    setResults({
                        students: data.results.students || [],
                        groups: data.results.groups || [],
                        notes: data.results.notes || [],
                        pages: matchedPages
                    })
                }
            } catch (error) {
                console.error('Search error', error)
                setResults(prev => ({ ...prev, pages: matchedPages }))
            } finally {
                setLoading(false)
            }
        }, 250)

        // Immediately show page matches
        setResults(prev => ({ ...prev, pages: matchedPages }))

        return () => clearTimeout(timer)
    }, [query])

    // Get flat list for keyboard navigation
    const flatResults = (() => {
        const all = []
        if (category === 'All' || category === 'Pages') all.push(...results.pages)
        if (category === 'All' || category === 'Students') all.push(...results.students)
        if (category === 'All' || category === 'Groups') all.push(...results.groups)
        if (category === 'All' || category === 'Notes') all.push(...results.notes)
        return all
    })()

    // Keyboard Navigation
    useEffect(() => {
        const handleNav = (e) => {
            if (!isOpen) return

            if (e.key === 'ArrowDown') {
                e.preventDefault()
                setSelectedIndex(prev => (prev + 1) % Math.max(1, flatResults.length))
            } else if (e.key === 'ArrowUp') {
                e.preventDefault()
                setSelectedIndex(prev => (prev - 1 + flatResults.length) % Math.max(1, flatResults.length))
            } else if (e.key === 'Enter') {
                e.preventDefault()
                if (flatResults[selectedIndex]) handleSelect(flatResults[selectedIndex])
            } else if (e.key === 'Tab') {
                e.preventDefault()
                // Cycle categories
                const idx = CATEGORIES.indexOf(category)
                setCategory(CATEGORIES[(idx + 1) % CATEGORIES.length])
                setSelectedIndex(0)
            }
        }

        window.addEventListener('keydown', handleNav)
        return () => window.removeEventListener('keydown', handleNav)
    }, [isOpen, flatResults, selectedIndex, category])

    const handleSelect = (item) => {
        if (item.type === 'student') {
            setSelectedStudent(item)
            closeSpotlight()
        } else if (item.type === 'group') {
            closeSpotlight()
            navigate('/groups')
        } else if (item.type === 'page') {
            closeSpotlight()
            navigate(item.path)
        } else if (item.type === 'note') {
            closeSpotlight()
            if (item.student_id) navigate('/students')
            else if (item.group_id) navigate('/groups')
        }
    }

    // Result type icon
    const getIcon = (item) => {
        if (item.type === 'page') return item.icon
        if (item.type === 'student') return '👤'
        if (item.type === 'group') return '🏘️'
        if (item.type === 'note') return '📝'
        return '📄'
    }

    // Result subtitle
    const getSubtitle = (item) => {
        if (item.type === 'student') return `${item.email || ''} · ${item.celebration_point || ''} · ${Math.round(item.percentage_completed || 0)}%`
        if (item.type === 'group') return `${item.group_code} · ${item.member_count || 0} members · ${item.facilitator_name || 'No facilitator'}`
        if (item.type === 'note') return `${item.author_name} · ${item.content?.slice(0, 60)}...`
        if (item.type === 'page') return item.description
        return ''
    }

    const totalCount = flatResults.length

    if (!isOpen && !selectedStudent) return null

    return (
        <>
            {isOpen && (
                <div className={`spotlight-overlay ${!query.trim() ? 'empty' : ''}`} onClick={closeSpotlight}>
                    <div className={`spotlight ${!query.trim() ? 'empty' : 'active'}`} onClick={e => e.stopPropagation()}>
                        {/* Always shown: Search Head area */}
                        <div className="spotlight-head">
                            <div className="spotlight-search-well">
                                <div className="spotlight-search-bar">
                                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="search-icon">
                                        <circle cx="11" cy="11" r="8"></circle>
                                        <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
                                    </svg>
                                    <input
                                        ref={inputRef}
                                        type="text"
                                        placeholder="Spotlight Search"
                                        value={query}
                                        onChange={e => { setQuery(e.target.value); setSelectedIndex(0) }}
                                        className="spotlight-input"
                                    />
                                    {query.trim() && <div className="keyboard-hint">esc</div>}
                                </div>
                            </div>

                            {/* The 4 Action Buttons - Now rendered always, but hidden via CSS in active state for smooth transition */}
                            <div className="spotlight-quick-actions">
                                <button className="sq-btn" title="Students" onClick={() => { closeSpotlight(); navigate('/students'); }}>
                                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M22 10v6M2 10l10-5 10 5-10 5z" /><path d="M6 12v5c3 3 9 3 12 0v-5" /></svg>
                                </button>
                                <button className="sq-btn" title="Groups" onClick={() => { closeSpotlight(); navigate('/groups'); }}>
                                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle><path d="M23 21v-2a4 4 0 0 0-3-3.87"></path><path d="M16 3.13a4 4 0 0 1 0 7.75"></path></svg>
                                </button>
                                <button className="sq-btn" title="Weekly Reports" onClick={() => { closeSpotlight(); navigate('/weekly-reports'); }}>
                                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect><line x1="3" y1="9" x2="21" y2="9"></line><line x1="9" y1="21" x2="9" y2="9"></line></svg>
                                </button>
                                <button className="sq-btn" title="Settings" onClick={() => { closeSpotlight(); navigate('/settings'); }}>
                                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="3"></circle><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"></path></svg>
                                </button>
                            </div>
                        </div>

                        {/* Category Tabs */}
                        {query.trim() && (
                            <div className="spotlight-tabs">
                                {CATEGORIES.map(cat => (
                                    <button
                                        key={cat}
                                        className={`spotlight-tab ${category === cat ? 'active' : ''}`}
                                        onClick={() => { setCategory(cat); setSelectedIndex(0) }}
                                    >
                                        {cat}
                                        {cat !== 'All' && (
                                            <span className="tab-count">
                                                {cat === 'Students' ? results.students.length :
                                                    cat === 'Groups' ? results.groups.length :
                                                        cat === 'Notes' ? results.notes.length :
                                                            results.pages.length}
                                            </span>
                                        )}
                                    </button>
                                ))}
                            </div>
                        )}

                        {/* Results */}
                        {(loading || totalCount > 0 || query.trim()) && (
                            <div className="spotlight-results">
                                {loading && totalCount === 0 ? (
                                    <div className="spotlight-message">
                                        <div className="spotlight-spinner"></div>
                                        Searching...
                                    </div>
                                ) : totalCount > 0 ? (
                                    <>
                                        {/* Pages Section */}
                                        {(category === 'All' || category === 'Pages') && results.pages.length > 0 && (
                                            <div className="result-section">
                                                <div className="section-label">Pages</div>
                                                {results.pages.map((item, i) => {
                                                    const globalIdx = flatResults.indexOf(item)
                                                    return (
                                                        <div key={`page-${i}`}
                                                            className={`spotlight-item ${globalIdx === selectedIndex ? 'active' : ''}`}
                                                            onClick={() => handleSelect(item)}
                                                            onMouseEnter={() => setSelectedIndex(globalIdx)}
                                                        >
                                                            <div className="item-icon emoji">{getIcon(item)}</div>
                                                            <div className="item-info">
                                                                <div className="item-name">{item.name}</div>
                                                                <div className="item-meta">{getSubtitle(item)}</div>
                                                            </div>
                                                            <div className="item-action">↵</div>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )}

                                        {/* Students Section */}
                                        {(category === 'All' || category === 'Students') && results.students.length > 0 && (
                                            <div className="result-section">
                                                <div className="section-label">Students</div>
                                                {results.students.map((item, i) => {
                                                    const globalIdx = flatResults.indexOf(item)
                                                    return (
                                                        <div key={`student-${item.id}`}
                                                            className={`spotlight-item ${globalIdx === selectedIndex ? 'active' : ''}`}
                                                            onClick={() => handleSelect(item)}
                                                            onMouseEnter={() => setSelectedIndex(globalIdx)}
                                                        >
                                                            <div className="item-icon avatar">{(item.name || '?').charAt(0)}</div>
                                                            <div className="item-info">
                                                                <div className="item-name">{item.name}</div>
                                                                <div className="item-meta">{getSubtitle(item)}</div>
                                                            </div>
                                                            {item.risk_score >= 50 && (
                                                                <span className="risk-badge">⚠️</span>
                                                            )}
                                                            <div className="item-action">↵</div>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )}

                                        {/* Groups Section */}
                                        {(category === 'All' || category === 'Groups') && results.groups.length > 0 && (
                                            <div className="result-section">
                                                <div className="section-label">Formation Groups</div>
                                                {results.groups.map((item, i) => {
                                                    const globalIdx = flatResults.indexOf(item)
                                                    return (
                                                        <div key={`group-${item.id}`}
                                                            className={`spotlight-item ${globalIdx === selectedIndex ? 'active' : ''}`}
                                                            onClick={() => handleSelect(item)}
                                                            onMouseEnter={() => setSelectedIndex(globalIdx)}
                                                        >
                                                            <div className="item-icon emoji">🏘️</div>
                                                            <div className="item-info">
                                                                <div className="item-name">{item.name}</div>
                                                                <div className="item-meta">{getSubtitle(item)}</div>
                                                            </div>
                                                            {!item.active && <span className="inactive-badge">Inactive</span>}
                                                            <div className="item-action">↵</div>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )}

                                        {/* Notes Section */}
                                        {(category === 'All' || category === 'Notes') && results.notes.length > 0 && (
                                            <div className="result-section">
                                                <div className="section-label">Notes</div>
                                                {results.notes.map((item, i) => {
                                                    const globalIdx = flatResults.indexOf(item)
                                                    return (
                                                        <div key={`note-${item.id}`}
                                                            className={`spotlight-item ${globalIdx === selectedIndex ? 'active' : ''}`}
                                                            onClick={() => handleSelect(item)}
                                                            onMouseEnter={() => setSelectedIndex(globalIdx)}
                                                        >
                                                            <div className="item-icon emoji">📝</div>
                                                            <div className="item-info">
                                                                <div className="item-name">{item.author_name}</div>
                                                                <div className="item-meta">{getSubtitle(item)}</div>
                                                            </div>
                                                            <div className="item-action">↵</div>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )}
                                    </>
                                ) : query.trim() && !loading ? (
                                    <div className="spotlight-message">No results found</div>
                                ) : null}
                            </div>
                        )}

                        {/* Footer hints (Tahoe Style) */}
                        <div className="spotlight-footer">
                            <span className="footer-hint"><kbd>↑↓</kbd> Navigate</span>
                            <span className="footer-hint"><kbd>↵</kbd> Open</span>
                            <span className="footer-hint"><kbd>Tab</kbd> Category</span>
                            <span className="footer-hint"><kbd>Esc</kbd> Close</span>
                        </div>
                    </div>
                </div>
            )}

            {selectedStudent && (
                <StudentDetailModal
                    student={selectedStudent}
                    onClose={() => setSelectedStudent(null)}
                    onStatusChange={() => { }}
                />
            )}

            <style>{`
                /* Container styles handled by .spotlight in index.css */
                .spotlight-overlay {
                    position: fixed;
                    top: 0;
                    left: 0;
                    width: 100vw;
                    height: 100vh;
                    background: rgba(0, 0, 0, 0.25);
                    backdrop-filter: blur(8px);
                    z-index: 9999;
                    display: flex;
                    align-items: flex-start;
                    justify-content: center;
                    padding-top: 60px;
                    transition: background 0.3s, backdrop-filter 0.3s;
                    animation: fadeOverlay 0.2s ease-out;
                }
                .spotlight-overlay.empty {
                    background: transparent;
                    backdrop-filter: none;
                    -webkit-backdrop-filter: none;
                }

                .spotlight-head {
                    display: flex;
                    align-items: center;
                    gap: 12px;
                    width: 100%;
                }

                .spotlight-search-well {
                    flex: 1;
                    height: 56px;
                    transition: all 0.3s cubic-bezier(0.32, 0.72, 0, 1);
                }

                /* Empty State: High Vibrancy Tahoe Glass */
                .spotlight.empty .spotlight-search-well {
                    background: rgba(255, 255, 255, 0.15);
                    backdrop-filter: blur(48px) saturate(200%);
                    -webkit-backdrop-filter: blur(48px) saturate(200%);
                    border: 1px solid rgba(255, 255, 255, 0.25);
                    border-radius: 999px;
                    box-shadow: 0 16px 48px rgba(0, 0, 0, 0.2), inset 0 1px 1px rgba(255,255,255,0.1);
                    overflow: hidden;
                    display: flex;
                }
                [data-theme="light"] .spotlight.empty .spotlight-search-well {
                    background: rgba(255,255,255,0.35);
                    border-color: rgba(255,255,255,0.5);
                }

                .spotlight.active .spotlight-search-well {
                    background: transparent;
                    border: none;
                    box-shadow: none;
                    width: 100%;
                }

                .spotlight-search-bar {
                    display: flex;
                    align-items: center;
                    padding: 0 24px;
                    height: 100%;
                    width: 100%;
                    border-bottom: 1px solid var(--separator);
                    position: relative;
                }
                .spotlight.empty .spotlight-search-bar {
                    border-bottom: none;
                }

                /* Quick Actions */
                .spotlight-quick-actions {
                    display: flex;
                    gap: 12px;
                    animation: fadeInFadeUp 0.3s cubic-bezier(0.32, 0.72, 0, 1) backwards;
                    transition: opacity 0.2s, max-width 0.3s cubic-bezier(0.32, 0.72, 0, 1), transform 0.2s;
                    max-width: 300px;
                    overflow: hidden;
                }
                .spotlight.active .spotlight-quick-actions {
                    opacity: 0;
                    max-width: 0;
                    margin-left: -12px; /* Pull the search bar flush */
                    transform: scale(0.95);
                    pointer-events: none;
                }
                
                @keyframes fadeInFadeUp {
                    from { opacity: 0; transform: translateY(10px) scale(0.95); }
                    to { opacity: 1; transform: translateY(0) scale(1); }
                }

                .sq-btn {
                    width: 56px;
                    height: 56px;
                    flex-shrink: 0;
                    border-radius: 50%;
                    background: rgba(255, 255, 255, 0.15);
                    backdrop-filter: blur(48px) saturate(200%);
                    -webkit-backdrop-filter: blur(48px) saturate(200%);
                    border: 1px solid rgba(255, 255, 255, 0.25);
                    box-shadow: 0 16px 48px rgba(0, 0, 0, 0.2), inset 0 1px 1px rgba(255,255,255,0.1);
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    color: rgba(255, 255, 255, 0.9);
                    cursor: pointer;
                    transition: transform 0.25s cubic-bezier(0.34, 1.56, 0.64, 1), background 0.2s;
                }
                [data-theme="light"] .sq-btn {
                    background: rgba(255,255,255,0.35);
                    border-color: rgba(255,255,255,0.5);
                    color: rgba(0, 0, 0, 0.8);
                }
                .sq-btn:hover {
                    transform: scale(1.08);
                    background: rgba(255, 255, 255, 0.25);
                }
                [data-theme="light"] .sq-btn:hover {
                    background: rgba(255, 255, 255, 0.5);
                }

                .search-icon {
                    color: var(--text-primary);
                    margin-right: 14px;
                    opacity: 0.8;
                }

                .spotlight-input {
                    flex: 1;
                    background: transparent !important;
                    border: none !important;
                    box-shadow: none !important;
                    backdrop-filter: none !important;
                    -webkit-backdrop-filter: none !important;
                    font-size: 20px;
                    color: var(--text-primary);
                    font-weight: 400;
                    line-height: normal;
                    outline: none !important;
                    font-family: inherit;
                    letter-spacing: -0.2px;
                    padding: 0 !important;
                }
                .spotlight-input::placeholder { color: var(--text-secondary); font-weight: 400; }

                .keyboard-hint {
                    font-size: 11px;
                    color: var(--text-tertiary);
                    border: 1px solid var(--separator);
                    padding: 4px 8px;
                    border-radius: 6px;
                    background: rgba(255,255,255,0.03);
                }

                /* Categories */
                .spotlight-tabs {
                    display: flex;
                    padding: 0 16px;
                    gap: 4px;
                    border-bottom: 1px solid var(--separator);
                    background: rgba(0,0,0,0.02);
                }

                .spotlight-tab {
                    padding: 10px 14px;
                    background: transparent;
                    border: none;
                    color: var(--text-secondary);
                    font-size: 13px;
                    font-weight: 500;
                    cursor: pointer;
                    position: relative;
                    transition: color 0.15s;
                }
                .spotlight-tab:hover { color: var(--text-primary); }
                .spotlight-tab.active {
                    color: var(--text-primary);
                }
                .spotlight-tab.active::after {
                    content: '';
                    position: absolute;
                    bottom: -1px;
                    left: 14px;
                    right: 14px;
                    height: 2px;
                    background: var(--text-primary);
                    border-radius: 2px 2px 0 0;
                }

                /* Results Area */
                .spotlight-results {
                    max-height: 480px;
                    overflow-y: auto;
                }
                .spotlight-results::-webkit-scrollbar { width: 6px; }
                .spotlight-results::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 3px; }

                .result-section { margin-bottom: 2px; }

                .section-label {
                    padding: 8px 18px 4px;
                    font-size: 11px;
                    font-weight: 600;
                    color: rgba(255,255,255,0.35);
                    text-transform: uppercase;
                    letter-spacing: 0.5px;
                }
                [data-theme="light"] .section-label { color: rgba(0,0,0,0.35); }

                .spotlight-item {
                    display: flex;
                    align-items: center;
                    padding: 8px 18px;
                    cursor: pointer;
                    transition: background 0.08s;
                    gap: 10px;
                }
                .spotlight-item.active, .spotlight-item:hover {
                    background: rgba(0, 122, 255, 0.55);
                }
                [data-theme="light"] .spotlight-item.active,
                [data-theme="light"] .spotlight-item:hover {
                    background: rgba(0, 122, 255, 0.18);
                }

                .item-icon {
                    width: 32px;
                    height: 32px;
                    border-radius: 8px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-weight: 600;
                    flex-shrink: 0;
                }
                .item-icon.avatar {
                    background: rgba(255,255,255,0.1);
                    color: white;
                    border-radius: 50%;
                    font-size: 14px;
                }
                [data-theme="light"] .item-icon.avatar {
                    background: rgba(0,0,0,0.08);
                    color: #1d1d1f;
                }
                .item-icon.emoji { font-size: 20px; }

                .item-info { flex: 1; min-width: 0; }
                .item-name {
                    font-size: 14px;
                    color: white;
                    font-weight: 500;
                    white-space: nowrap;
                    overflow: hidden;
                    text-overflow: ellipsis;
                }
                [data-theme="light"] .item-name { color: #1d1d1f; }

                .item-meta {
                    font-size: 11px;
                    color: rgba(255,255,255,0.5);
                    white-space: nowrap;
                    overflow: hidden;
                    text-overflow: ellipsis;
                }
                .spotlight-item.active .item-meta { color: rgba(255,255,255,0.75); }
                [data-theme="light"] .item-meta { color: rgba(0,0,0,0.45); }

                .item-action {
                    font-size: 11px;
                    color: rgba(255,255,255,0.25);
                    flex-shrink: 0;
                }

                .risk-badge, .inactive-badge {
                    font-size: 10px;
                    padding: 2px 6px;
                    border-radius: 4px;
                    flex-shrink: 0;
                    margin-right: 4px;
                }
                .risk-badge { background: rgba(255,59,48,0.2); color: #ff6961; }
                .inactive-badge { background: rgba(255,255,255,0.08); color: rgba(255,255,255,0.4); }

                .spotlight-message {
                    padding: 28px;
                    text-align: center;
                    color: rgba(255,255,255,0.35);
                    font-size: 14px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    gap: 8px;
                }
                [data-theme="light"] .spotlight-message { color: rgba(0,0,0,0.35); }

                .spotlight-spinner {
                    width: 16px; height: 16px;
                    border: 2px solid rgba(255,255,255,0.1);
                    border-top-color: rgba(255,255,255,0.5);
                    border-radius: 50%;
                    animation: spotSpin 0.6s linear infinite;
                }

                /* Footer */
                .spotlight-footer {
                    display: flex;
                    gap: 16px;
                    padding: 8px 18px;
                    border-top: 1px solid rgba(255,255,255,0.06);
                    font-size: 10px;
                    color: rgba(255,255,255,0.25);
                }
                [data-theme="light"] .spotlight-footer {
                    border-top-color: rgba(0,0,0,0.06);
                    color: rgba(0,0,0,0.3);
                }
                .spotlight-footer kbd {
                    background: rgba(255,255,255,0.08);
                    padding: 1px 4px;
                    border-radius: 3px;
                    font-family: inherit;
                    font-size: 10px;
                    margin-right: 2px;
                }
                [data-theme="light"] .spotlight-footer kbd { background: rgba(0,0,0,0.06); }

                @keyframes spotSlideDown {
                    from { opacity: 0; transform: scale(0.97) translateY(-12px); }
                    to { opacity: 1; transform: scale(1) translateY(0); }
                }
                @keyframes spotFadeIn {
                    from { opacity: 0; }
                    to { opacity: 1; }
                }
                @keyframes spotSpin {
                    to { transform: rotate(360deg); }
                }

                @media (max-width: 768px) {
                    .spotlight-overlay {
                        padding-top: 20px;
                        padding-left: 10px;
                        padding-right: 10px;
                    }
                    .spotlight-search-bar {
                        padding: 0 16px;
                    }
                    .spotlight-input {
                        font-size: 16px;
                    }
                    .spotlight-quick-actions {
                        gap: 8px;
                    }
                    .sq-btn {
                        width: 44px;
                        height: 44px;
                    }
                    .sq-btn svg {
                        width: 18px;
                        height: 18px;
                    }
                    .spotlight-tabs {
                        overflow-x: auto;
                        -webkit-overflow-scrolling: touch;
                    }
                    .spotlight-tabs::-webkit-scrollbar {
                        display: none;
                    }
                    .spotlight-footer {
                        display: none; /* Hide keyboard hints on mobile */
                    }
                }
            `}</style>
        </>
    )
}

export default SpotlightSearch
