import { useState, useEffect } from 'react'
import { CELEBRATION_POINTS } from '../App'
import { useAuth } from '../contexts/AuthContext'
import { useSettings } from '../contexts/SettingsContext'
import { useNavigate } from 'react-router-dom'
import StatsGrid from '../components/StatsGrid'
import Charts from '../components/Charts'
import AlertsBanner from '../components/AlertsBanner'
import FormationWidgets from '../components/FormationWidgets'

function Dashboard() {
    const { user, showToast } = useAuth()
    const { focusMode } = useSettings()
    const navigate = useNavigate()
    const [loading, setLoading] = useState(true)
    const [students, setStudents] = useState([])
    const [stats, setStats] = useState({})
    const [chartData, setChartData] = useState({})
    const [myGroups, setMyGroups] = useState([])
    const [selectedCelebration, setSelectedCelebration] = useState(
        ['Admin', 'LeadershipTeam', 'Pastor'].includes(user?.role) ? '' : user?.celebration_point
    )

    const isFacilitator = user?.role === 'Facilitator'

    useEffect(() => {
        loadData()
        if (isFacilitator) loadMyGroups()
    }, [selectedCelebration])

    const loadData = async () => {
        setLoading(true)
        try {
            const params = new URLSearchParams()
            if (selectedCelebration) {
                params.append('celebration_point', selectedCelebration)
            }

            const response = await fetch(`/api/data/students?${params}`)
            const data = await response.json()

            if (data.success) {
                setStudents(data.students || [])
                setStats(data.stats || {})
                setChartData(data.chartData || {})
            } else {
                showToast(data.message || 'Failed to load data', 'error')
            }
        } catch (error) {
            console.error('Load data error:', error)
            showToast('Failed to connect to server', 'error')
        } finally {
            setLoading(false)
        }
    }

    const loadMyGroups = async () => {
        try {
            const res = await fetch('/api/formation-groups')
            const data = await res.json()
            if (data.success) setMyGroups(data.groups || [])
        } catch (err) { /* ignore */ }
    }

    const handleNavigateToAlerts = () => {
        navigate('/students')
    }

    return (
        <div className="tahoe-page">
            {['Admin', 'LeadershipTeam', 'Pastor'].includes(user?.role) && (
                <div style={{ marginBottom: '24px' }}>
                    <select
                        className="filter-select"
                        value={selectedCelebration}
                        onChange={(e) => setSelectedCelebration(e.target.value)}
                        style={{ minWidth: '300px' }}
                    >
                        {['Admin', 'LeadershipTeam'].includes(user?.role) && (
                            <option value="">All Celebration Points</option>
                        )}
                        {CELEBRATION_POINTS.map(cp => (
                            <option key={cp} value={cp}>{cp}</option>
                        ))}
                    </select>
                    <button
                        className="btn-secondary"
                        onClick={loadData}
                        style={{ marginLeft: '12px' }}
                    >
                        🔄 Refresh Data
                    </button>
                </div>
            )}

            {/* Focus Mode indicator (Liquid Glass) */}
            {focusMode !== 'default' && (
                <div style={{
                    display: 'inline-flex', alignItems: 'center', gap: '10px',
                    padding: '8px 16px', borderRadius: 'var(--radius-pill)', marginBottom: '24px',
                    background: 'var(--glass-layer-2)', border: 'var(--border-layer-2)',
                    boxShadow: 'var(--shadow-layer-3)',
                    backdropFilter: 'var(--blur-layer-2)',
                    fontSize: '12px', color: 'var(--text-primary)',
                    animation: 'fadeIn 0.3s ease-out'
                }}>
                    <span style={{ fontSize: '14px' }}>🎯</span>
                    <span>Focus: <strong style={{ textTransform: 'capitalize', color: 'var(--primary-light)' }}>{focusMode}</strong></span>
                    <button
                        onClick={() => document.dispatchEvent(new CustomEvent('toggle-focus-mode', { detail: 'default' }))}
                        style={{
                            background: 'rgba(255,255,255,0.1)', border: 'none', borderRadius: '50%',
                            width: '20px', height: '20px', display: 'flex', alignItems: 'center', justifyContent: 'center',
                            cursor: 'pointer', marginLeft: '8px', color: 'var(--text-secondary)',
                            transition: 'all 0.2s'
                        }}
                        onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.2)'; e.currentTarget.style.color = 'var(--text-primary)' }}
                        onMouseLeave={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.1)'; e.currentTarget.style.color = 'var(--text-secondary)' }}
                        title="Clear Focus"
                    >
                        ✕
                    </button>
                    {/* Fallback to simple context update if event not wired, users can use Control Center */}
                </div>
            )}

            {loading ? (
                <div className="loading-container">
                    <div className="spinner"></div>
                    <p>Loading dashboard data...</p>
                </div>
            ) : (
                <>
                    {/* Alerts Summary Widget */}
                    <div onClick={handleNavigateToAlerts} style={{ cursor: 'pointer' }}>
                        <AlertsBanner
                            students={students}
                            onFilter={() => { }}
                        />
                    </div>

                    {/* High Level Metrics — hidden in facilitator focus */}
                    {focusMode !== 'facilitator' && (
                        <StatsGrid stats={stats} />
                    )}

                    {/* Visual Charts — hidden in facilitator/pastor focus */}
                    {focusMode !== 'facilitator' && (
                        <div style={{ marginTop: '24px' }}>
                            <Charts chartData={chartData} />
                        </div>
                    )}

                    {/* Formation Layer Widgets — always shown */}
                    <FormationWidgets campus={selectedCelebration} />

                    {/* Facilitator: My Groups Widget */}
                    {isFacilitator && myGroups.length > 0 && (
                        <div style={{ marginTop: 32 }}>
                            <h3 style={{ fontSize: 16, fontWeight: 600, color: 'var(--text-primary)', marginBottom: 16 }}>
                                📋 My Formation Groups
                            </h3>
                            <div style={{
                                display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
                                gap: 16
                            }}>
                                {myGroups.map(g => (
                                    <div
                                        key={g.id}
                                        onClick={() => navigate('/groups')}
                                        className="glass-card hover-card"
                                        style={{
                                            padding: 20, cursor: 'pointer',
                                            transition: 'transform 0.2s var(--ease-spring), box-shadow 0.2s var(--ease-spring)'
                                        }}
                                        onMouseEnter={(e) => {
                                            e.currentTarget.style.transform = 'translateY(-4px)'
                                            e.currentTarget.style.boxShadow = 'var(--shadow-layer-4)'
                                        }}
                                        onMouseLeave={(e) => {
                                            e.currentTarget.style.transform = 'translateY(0)'
                                            e.currentTarget.style.boxShadow = 'var(--shadow-layer-3)'
                                        }}
                                    >
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
                                            <span style={{
                                                padding: '4px 10px', borderRadius: 8, fontSize: 11, fontWeight: 700,
                                                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                                                color: 'white', letterSpacing: 0.5, boxShadow: '0 2px 6px rgba(118, 75, 162, 0.3)'
                                            }}>{g.group_code}</span>
                                            {g.is_overdue && (
                                                <span style={{
                                                    fontSize: 10, padding: '3px 8px', borderRadius: 6,
                                                    background: 'rgba(255, 59, 48, 0.1)', color: '#ff3b30',
                                                    border: '1px solid rgba(255, 59, 48, 0.2)', fontWeight: 600
                                                }}>Report Overdue</span>
                                            )}
                                        </div>
                                        <div style={{ fontSize: 15, fontWeight: 600, color: 'var(--text-primary)', marginBottom: 6 }}>
                                            {g.name}
                                        </div>
                                        <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>
                                            {g.member_count || 0} member{g.member_count !== 1 ? 's' : ''} · {g.celebration_point}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </>
            )}
        </div>
    )
}

export default Dashboard

