import { useState } from 'react'
import { useAuth } from '../contexts/AuthContext'

function AlertsBanner({ students, onFilter }) {
    const { user } = useAuth()

    // Calculate counts
    const redAlerts = students.filter(s => s.alertLevel === 'red').length
    const yellowAlerts = students.filter(s => s.alertLevel === 'yellow').length

    if (redAlerts === 0 && yellowAlerts === 0) return null

    return (
        <div className="alerts-banner" style={{
            marginBottom: '24px',
            borderLeft: '4px solid var(--warning)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '16px 24px',
            background: 'var(--glass-layer-2)',
            backdropFilter: 'var(--blur-layer-2)',
            border: 'var(--border-layer-2)',
            borderRadius: '16px',
            boxShadow: 'var(--shadow-layer-3)'
        }}>
            <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }}>
                {redAlerts > 0 && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: 'var(--error)' }}>
                        <span style={{ fontSize: '18px' }}>🛑</span>
                        <span style={{ fontWeight: '600' }}>{redAlerts} Students</span>
                        <span style={{ opacity: 0.8 }}>inactive {'>'} 30 days</span>
                    </div>
                )}

                {yellowAlerts > 0 && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: 'var(--warning)' }}>
                        <span style={{ fontSize: '18px' }}>⚠️</span>
                        <span style={{ fontWeight: '600' }}>{yellowAlerts} Students</span>
                        <span style={{ opacity: 0.8 }}>inactive {'>'} 14 days</span>
                    </div>
                )}
            </div>

            {(user?.role === 'Pastor' || user?.role === 'Admin' || user?.role === 'Coordinator') && (
                <button
                    className="btn-secondary"
                    onClick={() => onFilter && onFilter('alert')}
                    style={{
                        fontSize: '13px',
                        padding: '6px 16px',
                        background: 'rgba(255,255,255,0.08)',
                        border: '1px solid rgba(255,255,255,0.1)'
                    }}
                >
                    View Inactive Students
                </button>
            )}
        </div>
    )
}

export default AlertsBanner
