import { useEffect, useCallback } from 'react'
import { useLocation, useNavigate } from 'react-router-dom'

/**
 * Handoff — Session resume: saves and restores last-visited page + scroll position.
 * Runs invisibly. No UI.
 */
function Handoff() {
    const location = useLocation()
    const navigate = useNavigate()

    // Save current location on every navigation
    useEffect(() => {
        if (location.pathname !== '/login') {
            const session = {
                path: location.pathname,
                search: location.search,
                scroll: window.scrollY,
                timestamp: Date.now()
            }
            localStorage.setItem('handoff_session', JSON.stringify(session))
        }
    }, [location.pathname, location.search])

    // Save scroll position on scroll (debounced)
    useEffect(() => {
        let timeout
        const handleScroll = () => {
            clearTimeout(timeout)
            timeout = setTimeout(() => {
                const existing = localStorage.getItem('handoff_session')
                if (existing) {
                    const session = JSON.parse(existing)
                    session.scroll = window.scrollY
                    localStorage.setItem('handoff_session', JSON.stringify(session))
                }
            }, 200)
        }
        window.addEventListener('scroll', handleScroll, { passive: true })
        return () => {
            clearTimeout(timeout)
            window.removeEventListener('scroll', handleScroll)
        }
    }, [])

    // Restore session on mount (only once)
    useEffect(() => {
        const saved = localStorage.getItem('handoff_session')
        if (saved) {
            try {
                const session = JSON.parse(saved)
                // Only restore if session is less than 24 hours old
                const age = Date.now() - session.timestamp
                if (age < 24 * 60 * 60 * 1000 && session.path !== location.pathname) {
                    navigate(session.path + (session.search || ''), { replace: true })
                    // Restore scroll after navigation settles
                    setTimeout(() => {
                        window.scrollTo(0, session.scroll || 0)
                    }, 100)
                }
            } catch { /* ignore corrupt data */ }
        }
    }, []) // eslint-disable-line react-hooks/exhaustive-deps

    return null // No UI
}

export default Handoff
