import { useState, useEffect } from 'react'
import { useAuth } from '../contexts/AuthContext'
import { CELEBRATION_POINTS } from '../App'

function FormationGroups() {
    const { user, showToast } = useAuth()

    // State
    const [groups, setGroups] = useState([])
    const [loading, setLoading] = useState(true)
    const [selectedGroup, setSelectedGroup] = useState(null)
    const [groupDetail, setGroupDetail] = useState(null)
    const [detailLoading, setDetailLoading] = useState(false)
    const [filterCampus, setFilterCampus] = useState(
        ['Admin', 'LeadershipTeam'].includes(user?.role) ? '' : user?.celebration_point
    )
    const [showCreateModal, setShowCreateModal] = useState(false)
    const [showAddMemberModal, setShowAddMemberModal] = useState(false)
    const [showEditModal, setShowEditModal] = useState(false)
    const [facilitators, setFacilitators] = useState([])

    // Edit form
    const [editData, setEditData] = useState({
        name: '', celebration_point: '', facilitator_user_id: '', cohort: ''
    })

    // Create form
    const [formData, setFormData] = useState({
        name: '', celebration_point: '', facilitator_user_id: '', cohort: '2025'
    })

    // Add member form
    const [memberStudentId, setMemberStudentId] = useState('')
    const [studentSearchResults, setStudentSearchResults] = useState([])
    const [memberSearchQuery, setMemberSearchQuery] = useState('')

    // Group comments
    const [groupNotes, setGroupNotes] = useState([])
    const [newComment, setNewComment] = useState('')

    const isGlobalRole = ['Admin', 'LeadershipTeam'].includes(user?.role)
    const canCreate = user?.role === 'Admin'
    const canManageMembers = ['Admin', 'Coordinator'].includes(user?.role)

    // Load groups
    useEffect(() => { loadGroups() }, [filterCampus])

    const loadGroups = async () => {
        setLoading(true)
        try {
            const params = new URLSearchParams()
            if (filterCampus) params.append('celebration_point', filterCampus)
            const res = await fetch(`/api/formation-groups?${params}`)
            const data = await res.json()
            if (data.success) setGroups(data.groups)
            else showToast(data.message, 'error')
        } catch (err) {
            showToast('Failed to load groups', 'error')
        }
        setLoading(false)
    }

    const loadGroupDetail = async (groupId) => {
        setDetailLoading(true)
        try {
            const res = await fetch(`/api/formation-groups/${groupId}`)
            const data = await res.json()
            if (data.success) {
                setGroupDetail(data)
                setSelectedGroup(groupId)
                loadGroupNotes(groupId)
            }
        } catch (err) {
            showToast('Failed to load group details', 'error')
        }
        setDetailLoading(false)
    }

    const loadGroupNotes = async (groupId) => {
        try {
            const res = await fetch(`/api/data/notes/group/${groupId}`)
            const data = await res.json()
            if (data.success) setGroupNotes(data.notes || [])
        } catch (err) { /* ignore */ }
    }

    const handleAddComment = async () => {
        if (!newComment.trim()) return
        try {
            const res = await fetch('/api/data/notes', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    groupId: selectedGroup,
                    content: newComment,
                    celebrationPoint: groupDetail?.group?.celebration_point
                })
            })
            const data = await res.json()
            if (data.success) {
                showToast('Comment added', 'success')
                setNewComment('')
                loadGroupNotes(selectedGroup)
            } else {
                showToast(data.message, 'error')
            }
        } catch (err) {
            showToast('Failed to add comment', 'error')
        }
    }

    const loadFacilitators = async () => {
        try {
            const res = await fetch('/api/formation-groups/facilitators/available')
            const data = await res.json()
            if (data.success) setFacilitators(data.facilitators)
        } catch (err) { /* ignore */ }
    }

    // --- Constants ---
    const CAMPUS_CODES = {
        'Bbira': 'WBB', 'Bugolobi': 'WBG', 'Bweyogerere': 'WBW', 'Downtown': 'WDT',
        'Entebbe': 'WEN', 'Nakwero': 'WGN', 'Gulu': 'WGU', 'Jinja': 'WJJ',
        'Juba': 'WJB', 'Kansanga': 'WKA', 'Kyengera': 'WKY', 'Laminadera': 'WLM',
        'Lubowa': 'WLB', 'Mbarara': 'WMB', 'Mukono': 'WMK', 'Nansana': 'WNW',
        'Ntinda': 'WNT', 'Online': 'WON', 'Suubi': 'WSU'
    }

    const handleCreate = async (e) => {
        e.preventDefault()
        if (!formData.name || !formData.celebration_point) {
            showToast('Name and Celebration Point required', 'error')
            return
        }

        // Construct full group code
        let finalGroupCode = null
        if (formData.codeSuffix) {
            const prefix = CAMPUS_CODES[formData.celebration_point] || 'WXX'
            finalGroupCode = `${prefix}${formData.codeSuffix.padStart(3, '0')}` // Ensure 3 digits
        }

        try {
            const payload = {
                ...formData,
                group_code: finalGroupCode
            }

            const res = await fetch('/api/formation-groups', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            })
            const data = await res.json()
            if (data.success) {
                showToast(`Group ${data.group_code} created!`, 'success')
                setShowCreateModal(false)
                setFormData({ name: '', celebration_point: '', facilitator_user_id: '', cohort: '2025', codeSuffix: '' })
                loadGroups()
            } else {
                showToast(data.message, 'error')
            }
        } catch (err) {
            showToast('Failed to create group', 'error')
        }
    }

    // Auto-update prefix when campus changes (handled in render, just need state reset)
    useEffect(() => {
        if (showCreateModal) {
            setFormData(prev => ({ ...prev, codeSuffix: '' }))
        }
    }, [showCreateModal])

    // ... (rest of component) ...

    const searchStudents = async (query) => {
        setMemberSearchQuery(query)
        if (query.length < 2) { setStudentSearchResults([]); return }
        try {
            const params = new URLSearchParams({ search: query, limit: 10, type: 'enrolled' })
            if (groupDetail?.group?.celebration_point) {
                params.append('celebration_point', groupDetail.group.celebration_point)
            }
            const res = await fetch(`/api/data/users?${params}`)
            const data = await res.json()
            if (data.success) setStudentSearchResults(data.users || [])
        } catch (err) { /* ignore */ }
    }

    const addMember = async (studentId) => {
        try {
            const res = await fetch(`/api/formation-groups/${selectedGroup}/members`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ student_id: String(studentId) })
            })
            const data = await res.json()
            if (data.success) {
                showToast('Member added', 'success')
                loadGroupDetail(selectedGroup)
                setMemberSearchQuery('')
                setStudentSearchResults([])
            } else {
                showToast(data.message, 'error')
            }
        } catch (err) {
            showToast('Failed to add member', 'error')
        }
    }

    const removeMember = async (studentId) => {
        if (!confirm('Remove this student from the group?')) return
        try {
            const res = await fetch(`/api/formation-groups/${selectedGroup}/members/${studentId}`, {
                method: 'DELETE'
            })
            const data = await res.json()
            if (data.success) {
                showToast('Member removed', 'success')
                loadGroupDetail(selectedGroup)
            } else {
                showToast(data.message, 'error')
            }
        } catch (err) {
            showToast('Failed to remove member', 'error')
        }
    }

    // --- Edit & Deactivate Handlers ---
    const openEditModal = () => {
        const g = groupDetail?.group
        if (!g) return
        setEditData({
            name: g.name || '',
            celebration_point: g.celebration_point || '',
            facilitator_user_id: g.facilitator_user_id || '',
            cohort: g.cohort || '2025'
        })
        loadFacilitators()
        setShowEditModal(true)
    }

    const handleEditGroup = async (e) => {
        e.preventDefault()
        try {
            const res = await fetch(`/api/formation-groups/${selectedGroup}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(editData)
            })
            const data = await res.json()
            if (data.success) {
                showToast('Group updated', 'success')
                setShowEditModal(false)
                loadGroupDetail(selectedGroup)
                loadGroups()
            } else {
                showToast(data.message, 'error')
            }
        } catch (err) {
            showToast('Failed to update group', 'error')
        }
    }

    const handleDeactivateGroup = async () => {
        if (!confirm('Are you sure you want to deactivate this group? It will be hidden from the group list.')) return
        try {
            const res = await fetch(`/api/formation-groups/${selectedGroup}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ active: 0 })
            })
            const data = await res.json()
            if (data.success) {
                showToast('Group deactivated', 'success')
                setSelectedGroup(null)
                setGroupDetail(null)
                loadGroups()
            } else {
                showToast(data.message, 'error')
            }
        } catch (err) {
            showToast('Failed to deactivate group', 'error')
        }
    }

    // --- RENDER: GROUP DETAIL VIEW ---
    if (selectedGroup && groupDetail) {
        const { group, members, reports } = groupDetail
        return (
            <div className="page-container" style={{ padding: '24px', maxWidth: 1000, margin: '0 auto' }}>
                {/* Back Button */}
                <button
                    onClick={() => { setSelectedGroup(null); setGroupDetail(null) }}
                    style={{
                        background: 'none', border: 'none', color: 'var(--text-secondary)',
                        cursor: 'pointer', fontSize: 13, marginBottom: 16, display: 'flex', alignItems: 'center', gap: 6,
                        fontWeight: 500, transition: 'color 0.2s'
                    }}
                    onMouseEnter={e => e.target.style.color = 'var(--text-primary)'}
                    onMouseLeave={e => e.target.style.color = 'var(--text-secondary)'}
                >
                    ← Back to Groups
                </button>

                {/* Group Header Card */}
                <div style={{
                    background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-3)',
                    border: 'var(--border-layer-2)', borderRadius: 20,
                    padding: 32, marginBottom: 24,
                    boxShadow: 'var(--shadow-layer-3)'
                }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                        <div>
                            <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 8, fontWeight: 500, display: 'flex', gap: 8 }}>
                                <span style={{ background: 'var(--glass-layer-3)', padding: '2px 8px', borderRadius: 6 }}>{group.group_code}</span>
                                <span style={{ background: 'var(--glass-layer-3)', padding: '2px 8px', borderRadius: 6 }}>{group.celebration_point}</span>
                                <span style={{ background: 'var(--glass-layer-3)', padding: '2px 8px', borderRadius: 6 }}>Cohort {group.cohort}</span>
                            </div>
                            <h2 style={{ margin: 0, fontSize: 28, color: 'var(--text-primary)', fontWeight: 700, letterSpacing: '-0.01em' }}>{group.name}</h2>
                            <div style={{ fontSize: 15, color: 'var(--text-secondary)', marginTop: 8 }}>
                                Facilitator: <strong style={{ color: 'var(--text-primary)' }}>
                                    {group.facilitator_name || 'Unassigned'}
                                </strong>
                            </div>
                        </div>
                        <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
                            {canCreate && (
                                <>
                                    <button onClick={openEditModal} style={{
                                        padding: '8px 16px', borderRadius: 10, border: 'var(--border-layer-2)',
                                        background: 'var(--glass-layer-3)', color: 'var(--text-primary)', cursor: 'pointer',
                                        fontSize: 13, fontWeight: 600, transition: 'background 0.2s',
                                        boxShadow: 'var(--shadow-layer-1)'
                                    }}>✏️ Edit</button>
                                    <button onClick={handleDeactivateGroup} style={{
                                        padding: '8px 16px', borderRadius: 10, border: '1px solid rgba(255,59,48,0.2)',
                                        background: 'rgba(255,59,48,0.1)', color: '#ff3b30', cursor: 'pointer',
                                        fontSize: 13, fontWeight: 600, transition: 'background 0.2s'
                                    }}>Deactivate</button>
                                </>
                            )}
                            <div style={{
                                background: 'linear-gradient(135deg, var(--primary-color) 0%, var(--accent-color) 100%)',
                                borderRadius: 16, padding: '12px 24px', textAlign: 'center', color: 'white',
                                boxShadow: 'var(--shadow-layer-3)'
                            }}>
                                <div style={{ fontSize: 24, fontWeight: 800 }}>{members.length}</div>
                                <div style={{ fontSize: 12, opacity: 0.9, fontWeight: 600 }}>Members</div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* EDIT GROUP MODAL */}
                {showEditModal && (
                    <div style={{
                        position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10000,
                        backdropFilter: 'blur(5px)'
                    }} onClick={() => setShowEditModal(false)}>
                        <div style={{
                            background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-3)',
                            border: 'var(--border-layer-2)', borderRadius: 24,
                            padding: 32, width: 480, maxWidth: '90vw',
                            boxShadow: 'var(--shadow-layer-4)'
                        }} onClick={e => e.stopPropagation()}>
                            <h3 style={{ margin: '0 0 24px', fontSize: 20, color: 'var(--text-primary)', fontWeight: 600 }}>
                                Edit Group — {group.group_code}
                            </h3>
                            <form onSubmit={handleEditGroup}>
                                <div style={{ marginBottom: 16 }}>
                                    <label style={labelStyle}>Group Name</label>
                                    <input type="text" value={editData.name}
                                        onChange={e => setEditData({ ...editData, name: e.target.value })}
                                        required style={inputStyle} />
                                </div>
                                <div style={{ marginBottom: 16 }}>
                                    <label style={labelStyle}>Facilitator</label>
                                    <select value={editData.facilitator_user_id}
                                        onChange={e => setEditData({ ...editData, facilitator_user_id: e.target.value })}
                                        style={inputStyle}>
                                        <option value="">Unassigned</option>
                                        {facilitators
                                            .filter(f => !editData.celebration_point || f.celebration_point === editData.celebration_point)
                                            .map(f => (
                                                <option key={f.id} value={f.id}>{f.name} ({f.celebration_point})</option>
                                            ))}
                                    </select>
                                </div>
                                <div style={{ marginBottom: 24 }}>
                                    <label style={labelStyle}>Cohort</label>
                                    <input type="text" value={editData.cohort}
                                        onChange={e => setEditData({ ...editData, cohort: e.target.value })}
                                        style={inputStyle} />
                                </div>
                                <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
                                    <button type="button" onClick={() => setShowEditModal(false)} style={{
                                        padding: '10px 18px', borderRadius: 10, border: 'var(--border-layer-2)',
                                        background: 'transparent', color: 'var(--text-primary)', cursor: 'pointer', fontSize: 13,
                                        fontWeight: 500
                                    }}>Cancel</button>
                                    <button type="submit" style={{
                                        padding: '10px 24px', borderRadius: 10, border: 'none', cursor: 'pointer',
                                        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                                        color: 'white', fontWeight: 600, fontSize: 13,
                                        boxShadow: 'var(--shadow-layer-2)'
                                    }}>Save Changes</button>
                                </div>
                            </form>
                        </div>
                    </div>
                )}

                {/* Add Member Search (Admin/Coordinator) */}
                {canManageMembers && (
                    <div style={{
                        background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-3)',
                        border: 'var(--border-layer-2)', borderRadius: 16,
                        padding: 20, marginBottom: 20,
                        boxShadow: 'var(--shadow-layer-2)'
                    }}>
                        <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)', marginBottom: 12 }}>
                            Add Student to Group
                        </div>
                        <div style={{ position: 'relative' }}>
                            <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', opacity: 0.5, color: 'var(--text-secondary)' }}>🔍</span>
                            <input
                                type="text"
                                placeholder="Search by name or email..."
                                value={memberSearchQuery}
                                onChange={(e) => searchStudents(e.target.value)}
                                style={{
                                    width: '100%', padding: '12px 14px 12px 36px', borderRadius: 10,
                                    background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
                                    color: 'var(--text-primary)', fontSize: 14, outline: 'none', boxSizing: 'border-box',
                                    transition: 'background 0.2s'
                                }}
                                onFocus={(e) => e.target.style.background = 'var(--glass-layer-3)'}
                                onBlur={(e) => e.target.style.background = 'var(--glass-layer-1)'}
                            />
                        </div>
                        {studentSearchResults.length > 0 && (
                            <div style={{
                                marginTop: 12, maxHeight: 240, overflowY: 'auto',
                                borderRadius: 10, border: 'var(--border-layer-2)',
                                background: 'var(--glass-layer-1)'
                            }}>
                                {studentSearchResults.map(s => (
                                    <div key={s.id} style={{
                                        padding: '10px 14px', display: 'flex', justifyContent: 'space-between',
                                        alignItems: 'center', borderBottom: 'var(--border-layer-1)',
                                        cursor: 'pointer', transition: 'background 0.1s'
                                    }}
                                        onClick={() => addMember(s.id)}
                                        onMouseEnter={(e) => e.currentTarget.style.background = 'var(--glass-layer-2)'}
                                        onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                                    >
                                        <div>
                                            <div style={{ fontSize: 14, fontWeight: 500, color: 'var(--text-primary)' }}>
                                                {s.first_name} {s.last_name}
                                            </div>
                                            <div style={{ fontSize: 12, color: 'var(--text-secondary)' }}>{s.email}</div>
                                        </div>
                                        <button className="btn-primary" style={{ padding: '4px 12px', fontSize: 12 }}>+ Add</button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {/* Members Table */}
                <div style={{
                    background: 'var(--glass-bg)', backdropFilter: 'blur(20px)',
                    border: '1px solid var(--glass-border)', borderRadius: 12,
                    overflow: 'hidden'
                }}>
                    <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--glass-border)', fontSize: 13, fontWeight: 600, color: 'var(--text-primary)' }}>
                        Members ({members.length})
                    </div>
                    {members.length === 0 ? (
                        <div style={{ padding: 40, textAlign: 'center', color: 'var(--text-secondary)', fontSize: 14 }}>
                            No members yet. {canManageMembers && 'Use the search above to add students.'}
                        </div>
                    ) : (
                        <div className="table-responsive">
                            <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '400px' }}>
                                <thead>
                                    <tr style={{ borderBottom: '1px solid var(--glass-border)' }}>
                                        <th style={thStyle}>Student ID</th>
                                        <th style={thStyle}>Joined</th>
                                        {canManageMembers && <th style={thStyle}>Actions</th>}
                                    </tr>
                                </thead>
                                <tbody>
                                    {members.map(m => (
                                        <tr key={m.membership_id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                                            <td style={tdStyle}>{m.student_id}</td>
                                            <td style={tdStyle}>{new Date(m.joined_at).toLocaleDateString()}</td>
                                            {canManageMembers && (
                                                <td style={tdStyle}>
                                                    <button
                                                        onClick={() => removeMember(m.student_id)}
                                                        style={{
                                                            background: 'rgba(255,59,48,0.15)', border: 'none',
                                                            color: '#ff3b30', padding: '4px 10px', borderRadius: 6,
                                                            cursor: 'pointer', fontSize: 12
                                                        }}
                                                    >
                                                        Remove
                                                    </button>
                                                </td>
                                            )}
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>

                {/* Weekly Reports Timeline */}
                <div style={{
                    background: 'var(--glass-bg)', backdropFilter: 'blur(20px)',
                    border: '1px solid var(--glass-border)', borderRadius: 12,
                    overflow: 'hidden', marginTop: 20
                }}>
                    <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--glass-border)', fontSize: 13, fontWeight: 600, color: 'var(--text-primary)' }}>
                        📝 Weekly Reports ({(reports || []).length})
                    </div>
                    {(!reports || reports.length === 0) ? (
                        <div style={{ padding: 40, textAlign: 'center', color: 'var(--text-secondary)', fontSize: 14 }}>
                            No weekly reports submitted yet.
                        </div>
                    ) : (
                        <div style={{ padding: 12 }}>
                            {reports.map(r => {
                                const engagementColors = { high: '#00b894', medium: '#fdcb6e', low: '#ff7675' }
                                return (
                                    <div key={r.id} style={{
                                        padding: 14, marginBottom: 8, borderRadius: 10,
                                        border: '1px solid var(--glass-border)',
                                        background: 'rgba(255,255,255,0.02)'
                                    }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                                                <span style={{ fontSize: 14, fontWeight: 700, color: 'var(--text-primary)' }}>Week {r.week_number}</span>
                                                <span style={{
                                                    fontSize: 11, padding: '2px 8px', borderRadius: 10, fontWeight: 600,
                                                    background: `${engagementColors[r.engagement_level] || '#999'}22`,
                                                    color: engagementColors[r.engagement_level] || '#999',
                                                    border: `1px solid ${engagementColors[r.engagement_level] || '#999'}44`,
                                                    textTransform: 'capitalize'
                                                }}>{r.engagement_level || 'N/A'}</span>
                                            </div>
                                            <div style={{ fontSize: 11, color: 'var(--text-secondary)' }}>
                                                {r.submitted_at ? new Date(r.submitted_at).toLocaleDateString() : 'Unknown'}
                                            </div>
                                        </div>
                                        <div style={{ display: 'flex', gap: 16, fontSize: 12, color: 'var(--text-secondary)' }}>
                                            <span>👥 Attendance: <strong style={{ color: 'var(--text-primary)' }}>{r.attendance_count || '—'}</strong></span>
                                            <span>📊 By: {r.facilitator_name || 'Unknown'}</span>
                                        </div>
                                        {r.formation_evidence && (
                                            <div style={{ marginTop: 8, fontSize: 12, color: 'var(--text-secondary)', padding: '6px 10px', borderRadius: 6, background: 'rgba(0,184,148,0.08)', borderLeft: '3px solid #00b894' }}>
                                                <strong style={{ color: '#00b894' }}>Formation Evidence:</strong> {r.formation_evidence.length > 120 ? r.formation_evidence.slice(0, 120) + '…' : r.formation_evidence}
                                            </div>
                                        )}
                                        {r.pastoral_concerns && (
                                            <div style={{ marginTop: 6, fontSize: 12, color: 'var(--text-secondary)', padding: '6px 10px', borderRadius: 6, background: 'rgba(255, 118, 117, 0.08)', borderLeft: '3px solid #ff7675' }}>
                                                <strong style={{ color: '#ff7675' }}>Pastoral Concerns:</strong> {r.pastoral_concerns.length > 120 ? r.pastoral_concerns.slice(0, 120) + '…' : r.pastoral_concerns}
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    )}
                </div>

                {/* Group Comments */}
                <div style={{
                    background: 'var(--glass-bg)', backdropFilter: 'blur(20px)',
                    border: '1px solid var(--glass-border)', borderRadius: 12,
                    overflow: 'hidden', marginTop: 20
                }}>
                    <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--glass-border)', fontSize: 13, fontWeight: 600, color: 'var(--text-primary)' }}>
                        💬 Group Comments ({groupNotes.length})
                    </div>

                    {/* Add Comment Form */}
                    <div style={{ padding: 16, borderBottom: groupNotes.length > 0 ? '1px solid var(--glass-border)' : 'none' }}>
                        <div style={{ display: 'flex', gap: 10 }}>
                            <input
                                type="text" placeholder="Add a comment..."
                                value={newComment}
                                onChange={(e) => setNewComment(e.target.value)}
                                onKeyDown={(e) => { if (e.key === 'Enter') handleAddComment() }}
                                style={{
                                    flex: 1, padding: '10px 14px', borderRadius: 8,
                                    background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)',
                                    color: 'var(--text-primary)', fontSize: 13, outline: 'none'
                                }}
                            />
                            <button onClick={handleAddComment} style={{
                                padding: '8px 16px', borderRadius: 8, border: 'none', cursor: 'pointer',
                                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                                color: 'white', fontWeight: 600, fontSize: 12, whiteSpace: 'nowrap'
                            }}>Post</button>
                        </div>
                    </div>

                    {/* Comments List */}
                    {groupNotes.length > 0 && (
                        <div style={{ padding: 12 }}>
                            {groupNotes.map((n, idx) => (
                                <div key={n.id || idx} style={{
                                    padding: 12, marginBottom: 6, borderRadius: 8,
                                    background: 'rgba(255,255,255,0.02)', borderLeft: '3px solid #667eea'
                                }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                            <strong style={{ fontSize: 12, color: 'var(--text-primary)' }}>{n.author_name}</strong>
                                            {n.author_role && (
                                                <span style={{
                                                    fontSize: 10, padding: '1px 6px', borderRadius: 4,
                                                    background: 'rgba(102,126,234,0.15)', color: '#667eea'
                                                }}>{n.author_role}</span>
                                            )}
                                        </div>
                                        <span style={{ fontSize: 10, color: 'var(--text-secondary)' }}>
                                            {n.created_at ? new Date(n.created_at).toLocaleString() : ''}
                                        </span>
                                    </div>
                                    <div style={{ fontSize: 13, color: 'var(--text-secondary)', lineHeight: 1.5 }}>
                                        {n.content}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        )
    }

    return (
        <div className="page-container" style={{ padding: '24px', maxWidth: 1200, margin: '0 auto' }}>
            {/* Header */}
            <div style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24,
                background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-3)',
                padding: '16px 24px', borderRadius: 20, border: 'var(--border-layer-2)',
                boxShadow: 'var(--shadow-layer-2)'
            }}>
                <div>
                    <h1 style={{ margin: 0, fontSize: 22, color: 'var(--text-primary)' }}>Formation Groups</h1>
                    <p style={{ margin: '4px 0 0', fontSize: 13, color: 'var(--text-secondary)' }}>
                        {groups.length} group{groups.length !== 1 ? 's' : ''} found
                    </p>
                </div>
                <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
                    {isGlobalRole && (
                        <select
                            value={filterCampus}
                            onChange={(e) => setFilterCampus(e.target.value)}
                            style={{
                                padding: '8px 16px', borderRadius: 10,
                                background: 'var(--glass-layer-3)', border: 'var(--border-layer-2)',
                                color: 'var(--text-primary)', fontSize: 13, outline: 'none',
                                backdropFilter: 'var(--blur-layer-1)', cursor: 'pointer'
                            }}
                        >
                            {['Admin', 'LeadershipTeam'].includes(user?.role) && (
                                <option value="">All Campuses</option>
                            )}
                            {CELEBRATION_POINTS.map(cp => (
                                <option key={cp} value={cp}>{cp}</option>
                            ))}
                        </select>
                    )}

                    {canCreate && (
                        <button
                            onClick={() => { setShowCreateModal(true); loadFacilitators() }}
                            className="btn-primary"
                            style={{
                                padding: '8px 18px', fontSize: 13,
                                boxShadow: 'var(--shadow-layer-3)'
                            }}
                        >
                            + New Group
                        </button>
                    )}
                </div>
            </div>

            {/* Groups Grid */}
            {loading ? (
                <div style={{ textAlign: 'center', padding: 60, color: 'var(--text-secondary)' }}>
                    <div className="spinner" style={{ margin: '0 auto 12px' }}></div>
                    Loading groups...
                </div>
            ) : groups.length === 0 ? (
                <div style={{
                    textAlign: 'center', padding: 80, color: 'var(--text-secondary)',
                    background: 'var(--glass-bg)', backdropFilter: 'blur(20px)',
                    border: '1px solid var(--glass-border)', borderRadius: 16
                }}>
                    <div style={{ fontSize: 48, marginBottom: 12 }}>📋</div>
                    <div style={{ fontSize: 16, fontWeight: 600, marginBottom: 4 }}>No Formation Groups</div>
                    <div style={{ fontSize: 13 }}>
                        {canCreate ? 'Click "+ New Group" to create the first group.' : 'No groups have been created for your campus yet.'}
                    </div>
                </div>
            ) : (
                <div style={{
                    display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
                    gap: 16
                }}>
                    {groups.map(g => (
                        <div
                            key={g.id}
                            onClick={() => loadGroupDetail(g.id)}
                            className="glass-card"
                            style={{
                                padding: '24px', cursor: 'pointer',
                                transition: 'all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1)',
                                position: 'relative', overflow: 'hidden'
                            }}
                        >
                            <div style={{
                                position: 'absolute', top: 0, left: 0, width: '100%', height: '4px',
                                background: 'linear-gradient(90deg, var(--primary-color), var(--accent-color))',
                                opacity: 0.8
                            }}></div>

                            <div style={{
                                display: 'inline-block', padding: '4px 10px', borderRadius: 6,
                                background: 'var(--glass-layer-3)', border: 'var(--border-layer-1)',
                                color: 'var(--primary-light)', fontSize: 12, fontWeight: 700, letterSpacing: '0.5px',
                                marginBottom: 16
                            }}>
                                {g.group_code}
                            </div>

                            <h3 style={{ margin: '0 0 8px', fontSize: 17, fontWeight: 600, color: 'var(--text-primary)' }}>
                                {g.name}
                                {g.is_overdue && (
                                    <span style={{
                                        marginLeft: 8, fontSize: 10, padding: '2px 6px', borderRadius: 4,
                                        background: 'rgba(255, 59, 48, 0.15)', color: '#ff3b30', border: '1px solid rgba(255, 59, 48, 0.2)'
                                    }}>
                                        Overdue
                                    </span>
                                )}
                            </h3>

                            <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 4 }}>
                                📍 {g.celebration_point}
                            </div>
                            <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 4 }}>
                                👤 {g.facilitator_name || 'Unassigned'}
                            </div>
                            <div style={{
                                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                                marginTop: 16, paddingTop: 16, borderTop: 'var(--border-layer-1)'
                            }}>
                                <span style={{ fontSize: 12, color: 'var(--text-secondary)' }}>
                                    Cohort {g.cohort}
                                </span>
                                <span style={{
                                    fontSize: 13, fontWeight: 600,
                                    color: g.member_count > 0 ? 'var(--primary-light)' : 'var(--text-secondary)'
                                }}>
                                    {g.member_count} member{g.member_count !== 1 ? 's' : ''}
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* CREATE MODAL */}
            {showCreateModal && (
                <div style={{
                    position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10000,
                    backdropFilter: 'blur(5px)'
                }}
                    onClick={() => setShowCreateModal(false)}
                >
                    <div style={{
                        background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-3)',
                        border: 'var(--border-layer-2)', borderRadius: 20,
                        padding: 32, width: 440, maxWidth: '90vw',
                        boxShadow: 'var(--shadow-layer-4)'
                    }}
                        onClick={e => e.stopPropagation()}
                    >
                        <h3 style={{ margin: '0 0 24px', fontSize: 20, color: 'var(--text-primary)', fontWeight: 600 }}>
                            Create Formation Group
                        </h3>
                        <form onSubmit={handleCreate}>
                            <div style={{ marginBottom: 16 }}>
                                <label style={labelStyle}>Celebration Point</label>
                                <select
                                    value={formData.celebration_point}
                                    onChange={e => setFormData({ ...formData, celebration_point: e.target.value })}
                                    required style={inputStyle}
                                >
                                    <option value="">Select Campus...</option>
                                    {CELEBRATION_POINTS.map(cp => (
                                        <option key={cp} value={cp}>{cp}</option>
                                    ))}
                                </select>
                            </div>

                            {/* New Group Code Input */}
                            <div style={{ marginBottom: 16 }}>
                                <label style={labelStyle}>Group Code (Prefix - Number)</label>
                                <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                                    <div style={{
                                        padding: '10px 14px', borderRadius: 8,
                                        background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
                                        color: 'var(--text-primary)', fontSize: 14, userSelect: 'none',
                                        minWidth: 60, textAlign: 'center', fontWeight: 'bold'
                                    }}>
                                        {formData.celebration_point ? (CAMPUS_CODES[formData.celebration_point] || '---') : '---'}
                                    </div>
                                    <input
                                        type="text" placeholder="001"
                                        value={formData.codeSuffix || ''}
                                        onChange={e => {
                                            // Only allow numbers
                                            const val = e.target.value.replace(/[^0-9]/g, '')
                                            setFormData({ ...formData, codeSuffix: val })
                                        }}
                                        maxLength={3}
                                        style={{ ...inputStyle, textAlign: 'center', letterSpacing: 2, fontWeight: 'bold' }}
                                    />
                                </div>
                                <div style={{ fontSize: 11, color: 'var(--text-secondary)', marginTop: 6, paddingLeft: 4 }}>
                                    Full Code: {formData.celebration_point ? `${CAMPUS_CODES[formData.celebration_point]}${(formData.codeSuffix || '000').padStart(3, '0')}` : 'Select campus first'}
                                </div>
                            </div>

                            <div style={{ marginBottom: 16 }}>
                                <label style={labelStyle}>Group Name</label>
                                <input
                                    type="text" placeholder="e.g. Downtown Alpha Group"
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                    required
                                    style={inputStyle}
                                />
                            </div>

                            <div style={{ marginBottom: 16 }}>
                                <label style={labelStyle}>Facilitator</label>
                                <select
                                    value={formData.facilitator_user_id}
                                    onChange={e => setFormData({ ...formData, facilitator_user_id: e.target.value })}
                                    style={inputStyle}
                                >
                                    <option value="">Unassigned</option>
                                    {facilitators
                                        .filter(f => !formData.celebration_point || f.celebration_point === formData.celebration_point)
                                        .map(f => (
                                            <option key={f.id} value={f.id}>{f.name} ({f.celebration_point})</option>
                                        ))
                                    }
                                </select>
                            </div>
                            <div style={{ marginBottom: 24 }}>
                                <label style={labelStyle}>Cohort</label>
                                <input
                                    type="text" value={formData.cohort}
                                    onChange={e => setFormData({ ...formData, cohort: e.target.value })}
                                    style={inputStyle}
                                />
                            </div>
                            <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
                                <button
                                    type="button" onClick={() => setShowCreateModal(false)}
                                    style={{
                                        padding: '10px 18px', borderRadius: 10, border: 'var(--border-layer-2)',
                                        background: 'transparent', color: 'var(--text-primary)', cursor: 'pointer', fontSize: 13,
                                        fontWeight: 500
                                    }}
                                >Cancel</button>
                                <button type="submit" className="btn-primary" style={{ padding: '10px 24px', fontSize: 13, boxShadow: 'var(--shadow-layer-2)' }}>Create Group</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    )
}

// --- Style Constants ---
// --- Style Constants ---
const thStyle = {
    padding: '12px 20px', fontSize: 12, fontWeight: 600,
    color: 'var(--text-secondary)', textAlign: 'left',
    borderBottom: 'var(--border-layer-1)'
}
const tdStyle = {
    padding: '12px 20px', fontSize: 13, color: 'var(--text-primary)',
    borderBottom: 'var(--border-layer-1)'
}
const labelStyle = {
    display: 'block', fontSize: 13, fontWeight: 500,
    color: 'var(--text-secondary)', marginBottom: 6
}
const inputStyle = {
    width: '100%', padding: '12px 16px', borderRadius: 10,
    background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
    color: 'var(--text-primary)', fontSize: 14, outline: 'none', boxSizing: 'border-box',
    transition: 'background 0.2s'
}

export default FormationGroups
