import { useState, useEffect } from 'react'
import { useAuth } from '../contexts/AuthContext'
import { CELEBRATION_POINTS } from '../App'

function WeeklyReports() {
    const { user, showToast } = useAuth()

    const [reports, setReports] = useState([])
    const [loading, setLoading] = useState(true)
    const [selectedReport, setSelectedReport] = useState(null)
    const [syncStatus, setSyncStatus] = useState(null)

    // Filters
    const [filterCampus, setFilterCampus] = useState(
        ['Admin', 'LeadershipTeam'].includes(user?.role) ? '' : user?.celebration_point
    )
    const [filterWeek, setFilterWeek] = useState('')
    const [filterGroup, setFilterGroup] = useState('')
    const [groups, setGroups] = useState([])
    const [viewMode, setViewMode] = useState('list') // 'list' | 'summary'

    const isGlobalRole = ['Admin', 'LeadershipTeam'].includes(user?.role)
    const isAdmin = user?.role === 'Admin'

    useEffect(() => { loadReports(); loadGroups(); if (isAdmin) loadSyncStatus() }, [])
    useEffect(() => { loadReports() }, [filterCampus, filterWeek, filterGroup])

    const loadReports = async () => {
        setLoading(true)
        try {
            const params = new URLSearchParams()
            if (filterCampus) params.append('celebration_point', filterCampus)
            if (filterWeek) params.append('week', filterWeek)
            if (filterGroup) params.append('group_id', filterGroup)
            const res = await fetch(`/api/reports?${params}`)
            const data = await res.json()
            if (data.success) setReports(data.reports)
        } catch { showToast('Failed to load reports', 'error') }
        setLoading(false)
    }

    const loadGroups = async () => {
        try {
            const params = new URLSearchParams()
            if (filterCampus) params.append('celebration_point', filterCampus)
            const res = await fetch(`/api/formation-groups?${params}`)
            const data = await res.json()
            if (data.success) setGroups(data.groups)
        } catch { /* ignore */ }
    }

    const loadSyncStatus = async () => {
        try {
            const res = await fetch('/api/reports/sync-status')
            const data = await res.json()
            if (data.success) setSyncStatus(data)
        } catch { /* ignore */ }
    }

    const triggerSync = async () => {
        try {
            showToast('Syncing from Notion...', 'info')
            const res = await fetch('/api/reports/sync', { method: 'POST' })
            const data = await res.json()
            if (data.success) {
                showToast(data.message || 'Sync complete', 'success')
                loadSyncStatus()
                loadReports()
            } else {
                showToast(data.message || 'Sync failed', 'error')
            }
        } catch { showToast('Sync failed', 'error') }
    }

    const engagementBadge = (level) => {
        const colors = { high: '#34C759', medium: '#FF9500', low: '#FF3B30' }
        return (
            <span style={{
                display: 'inline-block', padding: '2px 8px', borderRadius: 6,
                fontSize: 11, fontWeight: 600, textTransform: 'capitalize',
                background: `${colors[level] || '#888'}22`, color: colors[level] || '#888'
            }}>{level || 'N/A'}</span>
        )
    }

    // --- DETAIL VIEW ---
    if (selectedReport) {
        return (
            <div className="page-container" style={{ padding: '24px', maxWidth: 800, margin: '0 auto' }}>
                <button
                    onClick={() => setSelectedReport(null)}
                    style={{
                        background: 'none', border: 'none', color: 'var(--text-secondary)',
                        cursor: 'pointer', fontSize: 13, marginBottom: 16, display: 'flex', alignItems: 'center', gap: 6,
                        fontWeight: 500, transition: 'color 0.2s'
                    }}
                    onMouseEnter={e => e.target.style.color = 'var(--text-primary)'}
                    onMouseLeave={e => e.target.style.color = 'var(--text-secondary)'}
                >← Back to Reports</button>

                <div className="glass-card" style={{
                    background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-3)',
                    border: 'var(--border-layer-2)', borderRadius: 20, padding: 32,
                    boxShadow: 'var(--shadow-layer-3)'
                }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 24 }}>
                        <div>
                            <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 8, fontWeight: 500, display: 'flex', gap: 8 }}>
                                <span style={{ background: 'var(--glass-layer-3)', padding: '2px 8px', borderRadius: 6 }}>{selectedReport.group_code}</span>
                                <span style={{ background: 'var(--glass-layer-3)', padding: '2px 8px', borderRadius: 6 }}>{selectedReport.celebration_point}</span>
                                <span style={{ background: 'var(--glass-layer-3)', padding: '2px 8px', borderRadius: 6 }}>Week {selectedReport.week_number}</span>
                            </div>
                            <h2 style={{ margin: 0, fontSize: 24, color: 'var(--text-primary)', fontWeight: 700 }}>{selectedReport.group_name}</h2>
                            <div style={{ fontSize: 14, color: 'var(--text-secondary)', marginTop: 8 }}>
                                Facilitator: <strong style={{ color: 'var(--text-primary)' }}>{selectedReport.facilitator_name || 'Unknown'}</strong>
                                {selectedReport.submitted_at && (
                                    <span> · Submitted {new Date(selectedReport.submitted_at).toLocaleDateString()}</span>
                                )}
                            </div>
                        </div>
                        {engagementBadge(selectedReport.engagement_level)}
                    </div>

                    {/* Report Categories */}
                    {[
                        { label: '📊 Attendance', value: selectedReport.attendance_count ? `${selectedReport.attendance_count} participants present` : null },
                        { label: '💬 Key Themes', value: selectedReport.key_themes },
                        { label: '🌱 Formation Evidence', value: selectedReport.formation_evidence },
                        { label: '🙏 Pastoral Concerns', value: selectedReport.pastoral_concerns },
                        { label: '❓ Questions to Escalate', value: selectedReport.questions_to_escalate },
                        { label: '🔧 Session Adjustments', value: selectedReport.session_adjustments },
                    ].map(({ label, value }) => value ? (
                        <div key={label} style={{ marginBottom: 16, padding: 16, borderRadius: 12, background: 'var(--glass-layer-3)', border: 'var(--border-layer-1)' }}>
                            <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--text-primary)', marginBottom: 6 }}>{label}</div>
                            <div style={{ fontSize: 14, color: 'var(--text-primary)', lineHeight: 1.6, whiteSpace: 'pre-wrap' }}>{value}</div>
                        </div>
                    ) : null)}
                </div>
            </div>
        )
    }

    // --- LIST VIEW ---
    return (
        <div className="page-container" style={{ padding: '24px', maxWidth: 1200, margin: '0 auto' }}>
            {/* Header */}
            <div className="glass-card" style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24,
                padding: '16px 24px', borderRadius: 20
            }}>
                <div>
                    <h1 style={{ margin: 0, fontSize: 22, color: 'var(--text-primary)' }}>Weekly Reports</h1>
                    <p style={{ margin: '4px 0 0', fontSize: 13, color: 'var(--text-secondary)' }}>
                        {reports.length} report{reports.length !== 1 ? 's' : ''} from Notion
                    </p>
                </div>
                <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                    {/* Sync Status Badge */}
                    {isAdmin && syncStatus && (
                        <div style={{
                            padding: '6px 12px', borderRadius: 8, fontSize: 11, fontWeight: 600,
                            background: syncStatus.status === 'success' ? 'rgba(52,199,89,0.1)' :
                                syncStatus.status === 'error' ? 'rgba(255,59,48,0.1)' :
                                    syncStatus.status === 'disabled' ? 'var(--glass-layer-1)' :
                                        'rgba(255,149,0,0.1)',
                            color: syncStatus.status === 'success' ? '#34C759' :
                                syncStatus.status === 'error' ? '#FF3B30' :
                                    syncStatus.status === 'disabled' ? 'var(--text-secondary)' :
                                        '#FF9500',
                            border: 'var(--border-layer-1)'
                        }}>
                            {syncStatus.status === 'disabled' ? '⚠ Not Configured' :
                                syncStatus.status === 'success' ? `✓ Synced ${syncStatus.lastSyncTime ? new Date(syncStatus.lastSyncTime).toLocaleTimeString() : ''}` :
                                    syncStatus.status === 'error' ? '✗ Sync Error' :
                                        '⟳ Syncing...'}
                        </div>
                    )}

                    {isAdmin && syncStatus?.configured && (
                        <button onClick={triggerSync} style={{
                            padding: '8px 16px', borderRadius: 10, border: 'var(--border-layer-2)',
                            background: 'var(--glass-layer-3)', color: 'var(--primary-color)', fontWeight: 600,
                            fontSize: 13, cursor: 'pointer', transition: 'background 0.2s',
                            boxShadow: 'var(--shadow-layer-1)'
                        }}>⟳ Sync Now</button>
                    )}
                </div>
            </div>

            {/* Filters */}
            <div style={{ display: 'flex', gap: 12, marginBottom: 24, flexWrap: 'wrap' }}>
                {isGlobalRole && (
                    <select value={filterCampus} onChange={e => setFilterCampus(e.target.value)}
                        style={{
                            padding: '10px 16px', borderRadius: 10, background: 'var(--glass-layer-2)',
                            border: 'var(--border-layer-2)', color: 'var(--text-primary)',
                            fontSize: 13, outline: 'none', backdropFilter: 'var(--blur-layer-1)', cursor: 'pointer'
                        }}>
                        {['Admin', 'LeadershipTeam'].includes(user?.role) && (
                            <option value="">All Campuses</option>
                        )}
                        {CELEBRATION_POINTS.map(cp => <option key={cp} value={cp}>{cp}</option>)}
                    </select>
                )}
                <select value={filterWeek} onChange={e => setFilterWeek(e.target.value)}
                    style={{
                        padding: '10px 16px', borderRadius: 10, background: 'var(--glass-layer-2)',
                        border: 'var(--border-layer-2)', color: 'var(--text-primary)',
                        fontSize: 13, outline: 'none', backdropFilter: 'var(--blur-layer-1)', cursor: 'pointer'
                    }}>
                    <option value="">All Weeks</option>
                    {Array.from({ length: 13 }, (_, i) => i + 1).map(w => (
                        <option key={w} value={w}>Week {w}</option>
                    ))}
                </select>
                <select value={filterGroup} onChange={e => setFilterGroup(e.target.value)}
                    style={{
                        padding: '10px 16px', borderRadius: 10, background: 'var(--glass-layer-2)',
                        border: 'var(--border-layer-2)', color: 'var(--text-primary)',
                        fontSize: 13, outline: 'none', backdropFilter: 'var(--blur-layer-1)', cursor: 'pointer'
                    }}>
                    <option value="">All Groups</option>
                    {groups.map(g => <option key={g.id} value={g.id}>{g.group_code} — {g.name}</option>)}
                </select>
            </div>

            {/* Reports List */}
            {loading ? (
                <div style={{ textAlign: 'center', padding: 60, color: 'var(--text-secondary)' }}>
                    <div className="spinner" style={{ margin: '0 auto 12px' }}></div>
                    Loading reports...
                </div>
            ) : reports.length === 0 ? (
                <div className="glass-card" style={{ textAlign: 'center', padding: 80 }}>
                    <div style={{ fontSize: 48, marginBottom: 12 }}>📝</div>
                    <div style={{ fontSize: 16, fontWeight: 600, marginBottom: 4, color: 'var(--text-primary)' }}>No Weekly Reports</div>
                    <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>
                        {syncStatus?.status === 'disabled'
                            ? 'Notion sync is not configured. Go to Settings to connect your Notion database.'
                            : 'No reports have been synced yet. Reports will appear here after the next Notion sync.'}
                    </div>
                </div>
            ) : (
                <div className="glass-card table-responsive" style={{ padding: 0, overflow: 'hidden' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '600px' }}>
                        <thead>
                            <tr style={{ background: 'var(--glass-layer-2)', borderBottom: 'var(--border-layer-1)' }}>
                                <th style={thStyle}>Week</th>
                                <th style={thStyle}>Group</th>
                                <th style={thStyle}>Campus</th>
                                <th style={thStyle}>Facilitator</th>
                                <th style={thStyle}>Attendance</th>
                                <th style={thStyle}>Engagement</th>
                                <th style={thStyle}>Submitted</th>
                            </tr>
                        </thead>
                        <tbody>
                            {reports.map(r => (
                                <tr key={r.id}
                                    onClick={() => setSelectedReport(r)}
                                    style={{ borderBottom: 'var(--border-layer-1)', cursor: 'pointer', transition: 'background 0.1s' }}
                                    onMouseEnter={e => e.currentTarget.style.background = 'var(--glass-layer-2)'}
                                    onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
                                >
                                    <td style={tdStyle}><strong>Week {r.week_number}</strong></td>
                                    <td style={tdStyle}>
                                        <span style={{ fontSize: 11, fontWeight: 700, color: 'var(--primary-light)', marginRight: 6 }}>{r.group_code}</span>
                                        {r.group_name}
                                    </td>
                                    <td style={tdStyle}>{r.celebration_point}</td>
                                    <td style={tdStyle}>{r.facilitator_name || '—'}</td>
                                    <td style={tdStyle}>{r.attendance_count || '—'}</td>
                                    <td style={tdStyle}>{engagementBadge(r.engagement_level)}</td>
                                    <td style={{ ...tdStyle, fontSize: 12 }}>
                                        {r.submitted_at ? new Date(r.submitted_at).toLocaleDateString() : '—'}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    )
}

// --- Styles ---
const thStyle = {
    padding: '12px 20px', fontSize: 12, fontWeight: 600,
    color: 'var(--text-secondary)', textAlign: 'left',
    borderBottom: 'var(--border-layer-1)'
}
const tdStyle = {
    padding: '12px 20px', fontSize: 13, color: 'var(--text-primary)',
    borderBottom: 'var(--border-layer-1)'
}
const filterStyle = {
    padding: '8px 12px', borderRadius: 8, background: 'var(--glass-bg)',
    border: '1px solid var(--glass-border)', color: 'var(--text-primary)',
    fontSize: 13, outline: 'none', backdropFilter: 'blur(12px)'
}
const backBtnStyle = {
    background: 'none', border: 'none', color: 'var(--text-primary)',
    cursor: 'pointer', fontSize: 14, marginBottom: 16, display: 'flex', alignItems: 'center', gap: 6
}
const syncBtnStyle = {
    padding: '6px 14px', borderRadius: 8, border: '1px solid var(--glass-border)',
    background: 'rgba(102,126,234,0.15)', color: '#667eea', fontWeight: 600,
    fontSize: 12, cursor: 'pointer'
}

export default WeeklyReports
