import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../contexts/AuthContext'
import TimeMachine from '../components/TimeMachine'


function AuditLogs() {
    const { user, showToast } = useAuth()
    const navigate = useNavigate()
    const [logs, setLogs] = useState([])
    const [loading, setLoading] = useState(true)
    const [searchTerm, setSearchTerm] = useState('')
    const [showTimeMachine, setShowTimeMachine] = useState(false)

    useEffect(() => {
        if (user && user.role !== 'Admin') {
            showToast('Access denied', 'error')
            navigate('/dashboard')
            return
        }

        fetchLogs()
    }, [user, navigate])

    const fetchLogs = async () => {
        setLoading(true)
        try {
            const res = await fetch('/api/admin/audit')
            const data = await res.json()
            if (data.success) {
                setLogs(data.logs)
            } else {
                showToast(data.message || 'Failed to fetch logs', 'error')
            }
        } catch (error) {
            console.error('Fetch audit logs error:', error)
            showToast('Failed to connect to server', 'error')
        } finally {
            setLoading(false)
        }
    }

    const filteredLogs = logs.filter(log =>
        log.user_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        log.details.toLowerCase().includes(searchTerm.toLowerCase()) ||
        log.action.toLowerCase().includes(searchTerm.toLowerCase())
    )

    return (
        <div className="tahoe-page">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
                <h1 style={{ fontSize: '24px', fontWeight: 'bold' }}>Audit Logs</h1>
                <div style={{ display: 'flex', gap: '12px' }}>
                    <input
                        type="text"
                        placeholder="Search logs..."
                        className="glass-input"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: '250px' }}
                    />
                    <button className="btn-secondary" onClick={() => setShowTimeMachine(true)} style={{ background: 'linear-gradient(135deg, #667eea, #764ba2)', color: 'white', border: 'none' }}>⏰ Time Machine</button>
                    <button className="btn-secondary" onClick={fetchLogs}>🔄 Refresh</button>
                </div>
            </div>

            <div className="glass-card" style={{ padding: '0', overflow: 'hidden' }}>
                {loading ? (
                    <div className="loading-container">
                        <div className="spinner"></div>
                        <p>Loading audit trail...</p>
                    </div>
                ) : (
                    <div className="table-container table-responsive" style={{ maxHeight: 'calc(100vh - 250px)', overflowY: 'auto' }}>
                        <table className="data-table">
                            <thead style={{ position: 'sticky', top: 0, background: 'var(--card-bg)', zIndex: 10 }}>
                                <tr>
                                    <th>Timestamp</th>
                                    <th>User</th>
                                    <th>Role</th>
                                    <th>Action</th>
                                    <th>Details</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredLogs.length === 0 ? (
                                    <tr>
                                        <td colSpan="5" style={{ textAlign: 'center', padding: '32px', color: 'var(--text-secondary)' }}>
                                            No logs found.
                                        </td>
                                    </tr>
                                ) : (
                                    filteredLogs.map(log => (
                                        <tr key={log.id}>
                                            <td style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
                                                {new Date(log.created_at).toLocaleString()}
                                            </td>
                                            <td>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                    <div style={{
                                                        width: '24px', height: '24px', borderRadius: '50%',
                                                        background: 'var(--accent-gradient)',
                                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                                        fontSize: '10px', fontWeight: 'bold', color: 'white'
                                                    }}>
                                                        {log.user_name.charAt(0)}
                                                    </div>
                                                    {log.user_name}
                                                </div>
                                            </td>
                                            <td>
                                                <span className="status-badge" style={{
                                                    background: log.role === 'Admin' ? 'rgba(255, 59, 48, 0.2)' : 'rgba(10, 132, 255, 0.2)',
                                                    color: log.role === 'Admin' ? 'var(--error)' : 'var(--info)'
                                                }}>
                                                    {log.role}
                                                </span>
                                            </td>
                                            <td style={{ fontWeight: '600' }}>{log.action}</td>
                                            <td style={{ color: 'var(--text-secondary)' }}>{log.details}</td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <TimeMachine
                logs={filteredLogs}
                isOpen={showTimeMachine}
                onClose={() => setShowTimeMachine(false)}
            />
        </div>
    )
}

export default AuditLogs
