import { useState, useEffect } from 'react'
import { useAuth } from '../contexts/AuthContext'
import { CELEBRATION_POINTS } from '../App'

function ReportExport() {
    const { user, showToast } = useAuth()

    const isGlobal = ['Admin', 'LeadershipTeam'].includes(user?.role)
    const isFacilitator = user?.role === 'Facilitator'
    const [campus, setCampus] = useState(isGlobal ? '' : user?.celebration_point)
    const [groups, setGroups] = useState([])
    const [selectedGroup, setSelectedGroup] = useState('')
    const [downloading, setDownloading] = useState(null)

    useEffect(() => { loadGroups() }, [])

    const loadGroups = async () => {
        try {
            const res = await fetch('/api/formation-groups')
            const data = await res.json()
            if (data.success) setGroups(data.groups || [])
        } catch { /* ignore */ }
    }

    const download = async (reportKey, url) => {
        setDownloading(reportKey)
        try {
            const separator = url.includes('?') ? '&' : '?'
            const fullUrl = campus && !url.includes('group/') ? `${url}${separator}celebration_point=${campus}` : url
            const res = await fetch(fullUrl)
            if (!res.ok) {
                const errData = await res.json().catch(() => ({}))
                throw new Error(errData.message || 'Download failed')
            }
            const blob = await res.blob()
            const disposition = res.headers.get('Content-Disposition') || ''
            const filename = disposition.match(/filename="(.+)"/)?.[1] || `report_${new Date().toISOString().slice(0, 10)}.csv`

            const a = document.createElement('a')
            a.href = URL.createObjectURL(blob)
            a.download = filename
            a.click()
            URL.revokeObjectURL(a.href)
            showToast(`Downloaded ${filename}`, 'success')
        } catch (err) {
            showToast(err.message || 'Download failed', 'error')
        }
        setDownloading(null)
    }

    const campusReports = [
        { key: 'roster', icon: '👥', title: 'Participant Roster', desc: 'Full roster with progress summary, risk scores, and activity.', url: '/api/exports/campus/roster' },
        { key: 'risk', icon: '⚠️', title: 'Inactivity / Risk Report', desc: 'At-risk participants sorted by risk score and inactivity days.', url: '/api/exports/campus/risk' },
        { key: 'weekly', icon: '📝', title: 'Weekly Report Aggregation', desc: 'All weekly reports with themes, evidence, and concerns.', url: '/api/exports/campus/weekly-reports' },
        { key: 'evidence', icon: '🌱', title: 'Formation Evidence Summary', desc: 'Formation observations and growth evidence from reports.', url: '/api/exports/campus/formation-evidence' },
        { key: 'checkpoints', icon: '🎯', title: 'Checkpoint Summary', desc: 'Discernment checkpoint data with review notes and trends.', url: '/api/exports/campus/checkpoints' },
    ]

    const filteredGroups = campus
        ? groups.filter(g => g.celebration_point === campus)
        : groups

    return (
        <div className="page-container" style={{ padding: 24, maxWidth: 960 }}>
            {/* Header */}
            <div style={{ marginBottom: 24 }}>
                <h1 style={{ margin: 0, fontSize: 24, color: 'var(--text-primary)' }}>Report Extraction</h1>
                <p style={{ margin: '4px 0 0', fontSize: 13, color: 'var(--text-secondary)' }}>
                    Download CSV reports for campus and formation group data
                </p>
            </div>

            {/* Campus Filter */}
            {isGlobal && (
                <div style={{ marginBottom: 20 }}>
                    <select value={campus} onChange={e => setCampus(e.target.value)} style={filterStyle}>
                        {['Admin', 'LeadershipTeam'].includes(user?.role) && (
                            <option value="">All Campuses</option>
                        )}
                        {CELEBRATION_POINTS.map(cp => <option key={cp} value={cp}>{cp}</option>)}
                    </select>
                </div>
            )}

            {/* Campus-Based Reports */}
            {!isFacilitator && (
                <>
                    <h2 style={sectionTitle}>📊 Campus-Based Reports</h2>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 14, marginBottom: 32 }}>
                        {campusReports.map(r => (
                            <div key={r.key} style={glassCard}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                                    <span style={{ fontSize: 22 }}>{r.icon}</span>
                                    <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>{r.title}</span>
                                </div>
                                <p style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.5, margin: '0 0 12px' }}>
                                    {r.desc}
                                </p>
                                <button onClick={() => download(r.key, r.url)} disabled={downloading === r.key}
                                    style={{ ...downloadBtnStyle, opacity: downloading === r.key ? 0.5 : 1 }}>
                                    {downloading === r.key ? '⏳ Generating...' : '📥 Download CSV'}
                                </button>
                            </div>
                        ))}
                    </div>
                </>
            )}

            {/* Group-Based Reports */}
            <h2 style={sectionTitle}>🏘️ Group-Based Reports</h2>

            {filteredGroups.length === 0 ? (
                <div style={{ ...glassCard, textAlign: 'center', padding: 40 }}>
                    <div style={{ fontSize: 36, marginBottom: 8 }}>🏘️</div>
                    <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>No groups available</div>
                </div>
            ) : (
                <>
                    <div style={{ marginBottom: 16 }}>
                        <select value={selectedGroup} onChange={e => setSelectedGroup(e.target.value)} style={filterStyle}>
                            <option value="">Select a Formation Group...</option>
                            {filteredGroups.map(g => (
                                <option key={g.id} value={g.id}>{g.group_code} — {g.name} ({g.celebration_point})</option>
                            ))}
                        </select>
                    </div>

                    {selectedGroup && (
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 14 }}>
                            <div style={glassCard}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                                    <span style={{ fontSize: 22 }}>👥</span>
                                    <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>Group Member Roster</span>
                                </div>
                                <p style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.5, margin: '0 0 12px' }}>
                                    Members with progress, activity, and risk scores.
                                </p>
                                <button onClick={() => download('group-roster', `/api/exports/group/${selectedGroup}/roster`)}
                                    disabled={downloading === 'group-roster'}
                                    style={{ ...downloadBtnStyle, opacity: downloading === 'group-roster' ? 0.5 : 1 }}>
                                    {downloading === 'group-roster' ? '⏳ Generating...' : '📥 Download CSV'}
                                </button>
                            </div>

                            <div style={glassCard}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                                    <span style={{ fontSize: 22 }}>📝</span>
                                    <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>Weekly Report History</span>
                                </div>
                                <p style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.5, margin: '0 0 12px' }}>
                                    All weekly reports submitted for this group.
                                </p>
                                <button onClick={() => download('group-weekly', `/api/exports/group/${selectedGroup}/weekly-reports`)}
                                    disabled={downloading === 'group-weekly'}
                                    style={{ ...downloadBtnStyle, opacity: downloading === 'group-weekly' ? 0.5 : 1 }}>
                                    {downloading === 'group-weekly' ? '⏳ Generating...' : '📥 Download CSV'}
                                </button>
                            </div>

                            <div style={glassCard}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                                    <span style={{ fontSize: 22 }}>🌱</span>
                                    <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>Formation Evidence Timeline</span>
                                </div>
                                <p style={{ fontSize: 12, color: 'var(--text-secondary)', lineHeight: 1.5, margin: '0 0 12px' }}>
                                    Weekly formation observations and growth evidence.
                                </p>
                                <button onClick={() => download('group-evidence', `/api/exports/group/${selectedGroup}/formation-evidence`)}
                                    disabled={downloading === 'group-evidence'}
                                    style={{ ...downloadBtnStyle, opacity: downloading === 'group-evidence' ? 0.5 : 1 }}>
                                    {downloading === 'group-evidence' ? '⏳ Generating...' : '📥 Download CSV'}
                                </button>
                            </div>
                        </div>
                    )}
                </>
            )}
        </div>
    )
}

// --- Styles ---
const glassCard = {
    background: 'var(--glass-bg)', backdropFilter: 'blur(20px)',
    border: '1px solid var(--glass-border)', borderRadius: 14, padding: 18
}
const filterStyle = {
    padding: '8px 14px', borderRadius: 8, background: 'var(--glass-bg)', width: '100%',
    border: '1px solid var(--glass-border)', color: 'var(--text-primary)',
    fontSize: 13, outline: 'none', backdropFilter: 'blur(12px)', maxWidth: '100%'
}
const sectionTitle = {
    fontSize: 15, fontWeight: 700, color: 'var(--text-primary)', marginBottom: 14,
    display: 'flex', alignItems: 'center', gap: 8
}
const downloadBtnStyle = {
    padding: '8px 16px', borderRadius: 8, border: 'none', cursor: 'pointer',
    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    color: 'white', fontWeight: 600, fontSize: 12, width: '100%'
}

export default ReportExport
