import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { CELEBRATION_POINTS } from '../App'
import { useAuth } from '../contexts/AuthContext'
import jsPDF from 'jspdf'

function Reports() {
    const { user, showToast } = useAuth()
    const navigate = useNavigate()
    const [loading, setLoading] = useState(false)
    const [selectedPoint, setSelectedPoint] = useState(
        ['Admin', 'LeadershipTeam'].includes(user?.role) ? '' : user?.celebration_point
    )

    useEffect(() => {
        if (user && user.role === 'Coordinator') {
            showToast('Access denied', 'error')
            navigate('/dashboard')
        }
    }, [user, navigate])

    const generatePDF = async (type) => {
        setLoading(true)
        try {
            // Re-fetch fresh data to ensure report is accurate
            const params = new URLSearchParams()
            if (selectedPoint) params.append('celebration_point', selectedPoint)

            const res = await fetch(`/api/data/students?${params}`)
            const data = await res.json()

            if (!data.success) throw new Error(data.message)

            const students = data.students
            const stats = data.stats

            // Generate PDF (Expanded version of Dashboard export)
            const doc = new jsPDF()
            const pageWidth = doc.internal.pageSize.getWidth()

            // Title
            doc.setFontSize(22)
            doc.setTextColor(99, 102, 241)
            doc.text(`${type} Report`, pageWidth / 2, 20, { align: 'center' })

            // Subtitle
            doc.setFontSize(14)
            doc.setTextColor(60, 60, 60)
            doc.text(`Location: ${selectedPoint || 'All Locations'}`, pageWidth / 2, 30, { align: 'center' })
            doc.text(`Date: ${new Date().toLocaleDateString()}`, pageWidth / 2, 38, { align: 'center' })

            let yPos = 50

            // Executive Summary
            doc.setFontSize(16)
            doc.setTextColor(0, 0, 0)
            doc.text('Executive Summary', 20, yPos)
            yPos += 10

            doc.setFontSize(11)
            doc.setTextColor(60, 60, 60)
            doc.text(`Total Students: ${stats.totalStudents}`, 20, yPos)
            doc.text(`Course Completion: ${Math.round((stats.completedCourses / (stats.totalStudents || 1)) * 100)}%`, 100, yPos)
            yPos += 8
            doc.text(`Active Students: ${stats.activeCourses}`, 20, yPos)
            doc.text(`Average Progress: ${stats.averageProgress}%`, 100, yPos)
            yPos += 15

            // Engagement Section
            doc.setFontSize(16)
            doc.setTextColor(0, 0, 0)
            doc.text('Engagement & Risks', 20, yPos)
            yPos += 10

            const redRisks = students.filter(s => s.alertLevel === 'red').length
            const yellowRisks = students.filter(s => s.alertLevel === 'yellow').length

            doc.setFontSize(11)
            doc.setTextColor(60, 60, 60)
            doc.text(`High Risk (Inactive > 30d): ${redRisks} students`, 20, yPos)
            yPos += 8
            doc.text(`Moderate Risk (Inactive > 14d): ${yellowRisks} students`, 20, yPos)
            yPos += 15

            // Student List (Filtered if High Risk Report)
            if (type === 'Risk Assessment') {
                doc.setFontSize(16)
                doc.setTextColor(0, 0, 0)
                doc.text('At-Risk Students', 20, yPos)
                yPos += 10

                const atRisk = students.filter(s => s.alertLevel === 'red' || s.alertLevel === 'yellow')

                atRisk.forEach(s => {
                    if (yPos > 270) { doc.addPage(); yPos = 20; }
                    doc.setFontSize(10)
                    doc.text(`• ${s.name} (${s.daysInactive} days inactive) - ${s.course}`, 20, yPos)
                    yPos += 6
                })

                if (atRisk.length === 0) {
                    doc.text('No at-risk students found.', 20, yPos)
                }
            } else {
                // Course Performance
                doc.setFontSize(16)
                doc.setTextColor(0, 0, 0)
                doc.text('Course Performance', 20, yPos)
                yPos += 10
                // Simplified list
                doc.setFontSize(10)
                doc.text('Detailed course breakdown available in Dashboard view.', 20, yPos)
            }

            doc.save(`${type.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.pdf`)
            showToast('Report generated successfully', 'success')

        } catch (error) {
            console.error('Report error:', error)
            showToast('Failed to generate report', 'error')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="tahoe-page">
            <div style={{ marginBottom: '24px' }}>
                <h1 style={{ fontSize: '24px', fontWeight: 'bold' }}>Reports Center</h1>
                <p style={{ color: 'var(--text-secondary)' }}>Generate and export detailed performance reports.</p>
            </div>

            {['Admin', 'LeadershipTeam'].includes(user?.role) && (
                <div style={{ marginBottom: '24px' }}>
                    <label style={{ marginRight: '12px', fontSize: '14px' }}>Select Location:</label>
                    <select
                        className="filter-select"
                        value={selectedPoint}
                        onChange={(e) => setSelectedPoint(e.target.value)}
                        style={{ minWidth: '250px' }}
                    >
                        {['Admin', 'LeadershipTeam'].includes(user?.role) && (
                            <option value="">All Locations</option>
                        )}
                        {CELEBRATION_POINTS.map(cp => (
                            <option key={cp} value={cp}>{cp}</option>
                        ))}
                    </select>
                </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '24px' }}>
                {/* Monthly Report Card */}
                <div className="glass-card">
                    <div style={{ padding: '24px' }}>
                        <div style={{ fontSize: '48px', marginBottom: '16px' }}>📊</div>
                        <h3 style={{ fontSize: '18px', marginBottom: '8px' }}>Monthly Overview</h3>
                        <p style={{ color: 'var(--text-secondary)', fontSize: '14px', marginBottom: '24px' }}>
                            Comprehensive summary of student enrollment, course completion rates, and overall progress for the selected location.
                        </p>
                        <button
                            className="btn-primary"
                            style={{ width: '100%' }}
                            onClick={() => generatePDF('Monthly Overview')}
                            disabled={loading}
                        >
                            {loading ? 'Generating...' : 'Download PDF'}
                        </button>
                    </div>
                </div>

                {/* Risk Assessment Card */}
                <div className="glass-card">
                    <div style={{ padding: '24px' }}>
                        <div style={{ fontSize: '48px', marginBottom: '16px' }}>⚠️</div>
                        <h3 style={{ fontSize: '18px', marginBottom: '8px' }}>Risk Assessment</h3>
                        <p style={{ color: 'var(--text-secondary)', fontSize: '14px', marginBottom: '24px' }}>
                            Detailed list of inactive students and engagement risks to prioritize pastoral follow-up and intervention.
                        </p>
                        <button
                            className="btn-secondary"
                            style={{ width: '100%' }}
                            onClick={() => generatePDF('Risk Assessment')}
                            disabled={loading}
                        >
                            {loading ? 'Generating...' : 'Download PDF'}
                        </button>
                    </div>
                </div>

                {/* Coordinator Performance (Placeholder) */}
                <div className="glass-card" style={{ opacity: 0.7 }}>
                    <div style={{ padding: '24px' }}>
                        <div style={{ fontSize: '48px', marginBottom: '16px' }}>👥</div>
                        <h3 style={{ fontSize: '18px', marginBottom: '8px' }}>Coordinator Performance</h3>
                        <p style={{ color: 'var(--text-secondary)', fontSize: '14px', marginBottom: '24px' }}>
                            analysis of coordinator engagement and student success rates by location.
                        </p>
                        <button className="btn-secondary" style={{ width: '100%' }} disabled>Coming Soon</button>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default Reports
