import { useState, useRef } from 'react'
import { useNavigate, useLocation } from 'react-router-dom'
import { useAuth } from '../contexts/AuthContext'
import { useSettings } from '../contexts/SettingsContext'

function Dock({ onAppClick }) {
    const { user } = useAuth()
    const { openSettings } = useSettings()
    const navigate = useNavigate()
    const location = useLocation()

    // Dock Items Configuration
    const dockItems = [
        { label: 'Dashboard', path: '/dashboard', icon: '🏠', color: 'linear-gradient(135deg, #FF9966 0%, #FF5E62 100%)' },
        { label: 'Students', path: '/students', icon: '🎓', role: ['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'TechSupport'], color: 'linear-gradient(135deg, #56CCF2 0%, #2F80ED 100%)' },
        { label: 'Users', path: '/admin', icon: '👥', role: ['Admin', 'TechSupport'], color: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)' },
        { label: 'Analytics', path: '/reports', icon: '📊', role: ['Admin', 'LeadershipTeam', 'Pastor'], color: 'linear-gradient(135deg, #8E2DE2 0%, #4A00E0 100%)' },
        { label: 'Audit', path: '/audit', icon: '🛡️', role: ['Admin', 'LeadershipTeam'], color: 'linear-gradient(135deg, #F2994A 0%, #F2C94C 100%)' },
        { label: 'Batch Tool', path: '/import', icon: '📦', role: ['Admin', 'Coordinator'], color: 'linear-gradient(135deg, #FF0099 0%, #493240 100%)' },
        { label: 'Groups', path: '/groups', icon: '🏘️', role: ['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator'], color: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' },
        { label: 'Weekly Reports', path: '/weekly-reports', icon: '📝', role: ['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator', 'TechSupport'], color: 'linear-gradient(135deg, #00b09b 0%, #96c93d 100%)' },
        { label: 'Checkpoints', path: '/checkpoints', icon: '🎯', role: ['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator', 'TechSupport'], color: 'linear-gradient(135deg, #e17055 0%, #d63031 100%)' },
        { label: 'Tech Support', path: '/tech-support', icon: '🔧', role: ['Admin', 'TechSupport'], color: 'linear-gradient(135deg, #0984e3 0%, #6c5ce7 100%)' },
        { label: 'Exports', path: '/exports', icon: '📥', role: ['Admin', 'LeadershipTeam', 'Pastor', 'Coordinator', 'Facilitator', 'TechSupport'], color: 'linear-gradient(135deg, #fd79a8 0%, #e84393 100%)' },
        { label: 'Settings', path: '/settings', icon: '⚙️', role: ['Admin'], color: 'linear-gradient(135deg, #636e72 0%, #2d3436 100%)' },
    ]

    const handleAppClick = (path) => {
        navigate(path)
        if (onAppClick) onAppClick()
    }

    const filteredItems = dockItems.filter(item => !item.role || item.role.includes(user?.role))

    // Add settings to the end built-in for mobile pagination logic
    const allItems = [...filteredItems, {
        label: 'System Preferences',
        path: '#', // Handled specially
        icon: '⚙️',
        color: 'linear-gradient(135deg, #8e9eab 0%, #eef2f3 100%)',
        isSettings: true
    }]

    // Chunk array into arrays of 4 for mobile
    const chunkedItems = []
    for (let i = 0; i < allItems.length; i += 4) {
        chunkedItems.push(allItems.slice(i, i + 4))
    }

    const [activePage, setActivePage] = useState(0)
    const scrollRef = useRef(null)

    const handleScroll = () => {
        if (scrollRef.current) {
            const scrollLeft = scrollRef.current.scrollLeft
            const width = scrollRef.current.clientWidth
            const page = Math.round(scrollLeft / width)
            if (page !== activePage) setActivePage(page)
        }
    }

    const renderIcon = (item, index) => {
        const isActive = !item.isSettings && location.pathname === item.path
        return (
            <div
                key={index}
                className={`dock-icon ${isActive ? 'active' : ''}`}
                onClick={() => item.isSettings ? openSettings() : handleAppClick(item.path)}
            >
                <div className="app-icon" style={{ background: item.color }}>
                    {item.icon}
                </div>
                {isActive && <div className="active-dot"></div>}
                {!isActive && item.isSettings && <div className="active-dot" style={{ opacity: 0 }}></div>}
                <div className="tooltip">{item.label}</div>
            </div>
        )
    }

    return (
        <div className="dock-container">
            {/* Desktop View */}
            <div className="dock dock-desktop">
                {filteredItems.map((item, index) => renderIcon(item, index))}

                <div className="dock-separator"></div>

                {renderIcon(allItems[allItems.length - 1], 'settings')}
            </div>

            {/* Mobile View (iOS 26 Paginated) */}
            <div className="dock-mobile-wrapper">
                <div className="dock dock-mobile" ref={scrollRef} onScroll={handleScroll}>
                    {chunkedItems.map((chunk, pageIndex) => (
                        <div key={`page-${pageIndex}`} className="dock-page">
                            {chunk.map((item, iconIndex) => renderIcon(item, `m-${pageIndex}-${iconIndex}`))}
                        </div>
                    ))}
                </div>
                {/* Pagination Dots */}
                {chunkedItems.length > 1 && (
                    <div className="dock-pagination">
                        {chunkedItems.map((_, i) => (
                            <div key={i} className={`dot ${i === activePage ? 'active' : ''}`}></div>
                        ))}
                    </div>
                )}
            </div>

            <style>{`
                .dock-container {
                    position: fixed;
                    bottom: 20px;
                    left: 0;
                    width: 100%;
                    display: flex;
                    justify-content: center;
                    z-index: 9999;
                    pointer-events: none; /* Let clicks pass through outside dock */
                }

                .dock-glass {
                    /* Handled by .dock class in index.css */
                    height: 100%;
                    display: flex;
                    align-items: center;
                    gap: 12px;
                }
                
                [data-theme="dark"] .dock-glass {
                    /* Sub-elements override if needed */
                }

                .dock-icon {
                    position: relative;
                    display: flex;
                    flex-direction: column;
                    align-items: center;
                    cursor: pointer;
                    transition: transform 280ms cubic-bezier(0.22, 1, 0.36, 1);
                }

                .dock-icon:hover {
                    transform: translateY(-8px) scale(1.15);
                }

                /* App Icon Style */
                .app-icon {
                    width: 48px;
                    height: 48px;
                    border-radius: 14px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 24px;
                    color: white;
                    box-shadow: 0 4px 10px rgba(0,0,0,0.2);
                    position: relative;
                    overflow: hidden;
                }
                
                .app-icon.settings {
                    background: linear-gradient(135deg, #8e9eab 0%, #eef2f3 100%);
                    color: #333;
                }

                /* Active Indicator */
                .active-dot {
                    width: 4px;
                    height: 4px;
                    background: rgba(255,255,255,0.8);
                    border-radius: 50%;
                    margin-top: 4px;
                    position: absolute;
                    bottom: -6px;
                }
                [data-theme="dark"] .active-dot { background: rgba(255,255,255,0.6); }

                /* Separator */
                .dock-separator {
                    width: 1px;
                    height: 32px;
                    background: rgba(255,255,255,0.2);
                    margin: 0 4px;
                }

                /* Tooltip (Apple HIG: Glass Layer 4) */
                .tooltip {
                    position: absolute;
                    top: -40px;
                    background: rgba(255,255,255,0.10);
                    backdrop-filter: blur(20px) saturate(160%);
                    -webkit-backdrop-filter: blur(20px) saturate(160%);
                    color: var(--text-primary);
                    padding: 5px 12px;
                    border-radius: 8px;
                    border: 0.5px solid rgba(255,255,255,0.15);
                    box-shadow: 0 8px 24px rgba(0,0,0,0.2);
                    font-family: var(--font-ui);
                    font-size: var(--text-caption-1);
                    font-weight: 500;
                    opacity: 0;
                    transform: translateY(6px);
                    transition: all 200ms cubic-bezier(0.22, 1, 0.36, 1);
                    pointer-events: none;
                    white-space: nowrap;
                }
                
                .dock-icon:hover .tooltip {
                    opacity: 1;
                    transform: translateY(0);
                }

                /* Desktop Only */
                .dock-mobile-wrapper { display: none; }
                .dock-desktop { display: flex; }

                /* Responsive */
                @media (max-width: 768px) {
                    .dock-desktop { display: none; }
                    .dock-mobile-wrapper {
                        display: flex;
                        flex-direction: column;
                        align-items: center;
                        width: 100%;
                        padding-bottom: env(safe-area-inset-bottom, 12px);
                    }

                    .dock-container {
                        bottom: 0px;
                        pointer-events: auto;
                    }

                    .dock.dock-mobile {
                        width: calc(100% - 32px); /* float above edges */
                        margin: 0 16px 12px 16px;
                        border-radius: 36px;
                        background: var(--glass-layer-3);
                        backdrop-filter: blur(40px) saturate(200%);
                        -webkit-backdrop-filter: blur(40px) saturate(200%);
                        border: 1px solid rgba(255,255,255,0.2);
                        box-shadow: 0 10px 40px rgba(0,0,0,0.15);
                        padding: 12px 16px;
                        
                        overflow-x: auto;
                        scroll-snap-type: x mandatory;
                        flex-wrap: nowrap;
                        justify-content: flex-start;
                        gap: 0;
                        scrollbar-width: none; /* Firefox */
                    }

                    .dock.dock-mobile::-webkit-scrollbar {
                        display: none; /* Chrome/Safari */
                    }

                    .dock-page {
                        min-width: 100%;
                        display: flex;
                        justify-content: center;
                        gap: 24px;
                        scroll-snap-align: center;
                        padding: 0;
                    }
                    
                    /* Remove the top reflection gradient line on mobile */
                    .dock.dock-mobile::after {
                         display: none;
                    }

                    .app-icon {
                        width: 48px;
                        height: 48px;
                        border-radius: 14px;
                        font-size: 24px;
                    }
                    
                    .dock-icon:hover {
                         transform: none; /* No hover lift on touch */
                    }

                    .tooltip {
                        display: none; /* Hide tooltips on touch devices */
                    }

                    .dock-pagination {
                        display: flex;
                        justify-content: center;
                        gap: 6px;
                        margin-bottom: 8px;
                    }

                    .dock-pagination .dot {
                        width: 6px;
                        height: 6px;
                        border-radius: 50%;
                        background: rgba(255,255,255,0.25);
                        transition: background 0.3s;
                    }
                    [data-theme="light"] .dock-pagination .dot {
                        background: rgba(0,0,0,0.15);
                    }

                    .dock-pagination .dot.active {
                        background: rgba(255,255,255,0.9);
                    }
                    [data-theme="light"] .dock-pagination .dot.active {
                        background: rgba(0,0,0,0.7);
                    }
                }

            `}</style>
        </div>
    )
}

export default Dock
