import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../contexts/AuthContext'
import { useSettings } from '../contexts/SettingsContext'
import { useNotifications } from '../contexts/NotificationContext'
import { useSpotlight } from '../contexts/SpotlightContext'
import ControlCenter from './ControlCenter'

function MenuBar() {
    const { user, logout } = useAuth()
    const navigate = useNavigate()
    const { openSettings } = useSettings()
    const { unreadCount, toggleCenter } = useNotifications()
    const { toggleSpotlight } = useSpotlight()
    const [time, setTime] = useState(new Date())
    const [isUserMenuOpen, setIsUserMenuOpen] = useState(false)
    const [isControlCenterOpen, setIsControlCenterOpen] = useState(false)

    useEffect(() => {
        const timer = setInterval(() => setTime(new Date()), 60000)
        return () => clearInterval(timer)
    }, [])

    const formatDate = (date) => {
        return date.toLocaleDateString('en-US', {
            weekday: 'short', day: 'numeric', month: 'short',
            hour: 'numeric', minute: '2-digit',
        })
    }

    return (
        <header className="tahoe-menubar">
            <div className="menubar-left">
                <div className="menu-item app-name font-bold">{user?.role || 'Dashboard'}</div>
            </div>

            <div className="menubar-right">
                {/* Icons: Search & Bell */}
                <div className="menu-item icon-btn" onClick={toggleSpotlight} title="Spotlight Search (Cmd+K)">
                    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                        <circle cx="11" cy="11" r="8"></circle>
                        <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
                    </svg>
                </div>

                {/* Control Center Icon */}
                <div className="menu-item icon-btn" onClick={() => setIsControlCenterOpen(!isControlCenterOpen)} title="Control Center">
                    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <rect x="3" y="3" width="7" height="7" rx="1.5"></rect>
                        <rect x="14" y="3" width="7" height="7" rx="1.5"></rect>
                        <rect x="3" y="14" width="7" height="7" rx="1.5"></rect>
                        <rect x="14" y="14" width="7" height="7" rx="1.5"></rect>
                    </svg>
                </div>

                <div className="menu-item icon-btn" onClick={toggleCenter} title="Notifications" style={{ position: 'relative' }}>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path>
                        <path d="M13.73 21a2 2 0 0 1-3.46 0"></path>
                    </svg>
                    {unreadCount > 0 && (
                        <span className="badge-dot"></span>
                    )}
                </div>

                {/* Clock */}
                <div className="menu-item clock">
                    {formatDate(time)}
                </div>

                {/* User Menu (Fast Switching) */}
                {user && (
                    <div
                        className={`menu-item user-profile ${isUserMenuOpen ? 'active' : ''}`}
                        onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
                    >
                        <span className="user-name">{user.name}</span>
                        <div className="avatar-tiny">
                            {user.profile_image ? (
                                <img src={user.profile_image} alt={user.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                            ) : (
                                user.name.charAt(0)
                            )}
                        </div>

                        {/* Dropdown */}
                        {isUserMenuOpen && (
                            <div className="menubar-dropdown">
                                <div className="dropdown-header">
                                    <div className="avatar-large">
                                        {user.profile_image ? (
                                            <img src={user.profile_image} alt={user.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                        ) : (
                                            user.name.charAt(0)
                                        )}
                                    </div>
                                    <div className="user-details">
                                        <div className="name">{user.name}</div>
                                        <div className="role">{user.role}</div>
                                    </div>
                                </div>
                                <div className="dropdown-divider"></div>
                                <button onClick={() => navigate('/dashboard')} className="dropdown-item">Dashboard</button>
                                <button onClick={() => { setIsUserMenuOpen(false); openSettings(); }} className="dropdown-item">System Preferences...</button>
                                <div className="dropdown-divider"></div>
                                <button onClick={logout} className="dropdown-item danger">Log Out...</button>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Control Center Panel */}
            <ControlCenter isOpen={isControlCenterOpen} onClose={() => setIsControlCenterOpen(false)} />

            <style>{`
                .tahoe-menubar {
                    /* Uses standard .menu-bar class from index.css */
                    composes: menu-bar from global;
                    width: 100%;
                    display: flex;
                    justify-content: space-between;
                    align-items: center;
                    padding: 0 16px;
                    position: fixed;
                    top: 0;
                    left: 0;
                    z-index: 9999;
                    font-family: var(--font-ui);
                    font-size: var(--text-footnote);
                    color: rgba(0, 0, 0, 0.85);
                    user-select: none;
                }
                [data-theme="dark"] .tahoe-menubar {
                     color: rgba(255, 255, 255, 0.9);
                }

                .menubar-left, .menubar-right {
                    display: flex;
                    align-items: center;
                    gap: 4px;
                }

                .menubar-right {
                    gap: 16px;
                }

                .menu-item {
                    padding: 4px 10px;
                    border-radius: 4px;
                    cursor: default;
                    transition: background 0.15s;
                }

                .menu-item:hover {
                    background: rgba(255, 255, 255, 0.2);
                }
                [data-theme="dark"] .menu-item:hover {
                    background: rgba(255, 255, 255, 0.1);
                }

                .app-name {
                    font-weight: 700;
                }

                .clock {
                    font-feature-settings: "tnum";
                    font-variant-numeric: tabular-nums;
                    font-weight: 500;
                }

                .user-profile {
                    display: flex;
                    align-items: center;
                    gap: 8px;
                    padding-right: 0;
                    position: relative;
                }

                .user-name {
                    font-weight: 500;
                }

                .avatar-tiny {
                    width: 20px;
                    height: 20px;
                    background: rgba(128,128,128,0.3);
                    border-radius: 50%;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 10px;
                    font-weight: 700;
                    border: 1px solid rgba(0,0,0,0.1);
                    overflow: hidden; /* Added for image clipping */
                }
                [data-theme="dark"] .avatar-tiny { border-color: rgba(255,255,255,0.1); }

                /* Dropdown */
                /* Dropdown uses liquid-glass + lg-thin */
                .menubar-dropdown {
                    @apply liquid-glass lg-thin; /* Conceptual - applying classes manually below */
                    position: absolute;
                    top: 100%;
                    right: 0;
                    margin-top: 6px;
                    width: 240px;
                    background: rgba(245, 245, 245, 0.65); /* Fallback/Blend */
                    backdrop-filter: blur(var(--lg-thin-blur));
                    -webkit-backdrop-filter: blur(var(--lg-thin-blur));
                    border-radius: var(--lg-radius-sm);
                    border: 1px solid rgba(255,255,255,0.2);
                    box-shadow: 0 10px 40px rgba(0,0,0,0.2);
                    padding: 6px;
                    display: flex;
                    flex-direction: column;
                    z-index: 10000;
                }
                [data-theme="dark"] .menubar-dropdown {
                    background: rgba(40, 40, 40, 0.65);
                    color: white;
                    border-color: rgba(255,255,255,0.1);
                }

                .dropdown-header {
                    display: flex;
                    align-items: center;
                    gap: 12px;
                    padding: 8px 10px;
                }

                .avatar-large {
                    width: 42px;
                    height: 42px;
                    border-radius: 50%;
                    background: var(--accent-gradient, linear-gradient(135deg, #007aff, #00c6ff));
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 18px;
                    font-weight: 600;
                    color: white;
                    text-shadow: 0 1px 2px rgba(0,0,0,0.2);
                    overflow: hidden; /* Added for image clipping */
                }

                .user-details .name { font-weight: 600; font-size: var(--text-subheadline); }
                .user-details .role { font-size: var(--text-caption-1); opacity: 0.6; }

                .dropdown-divider {
                    height: 1px;
                    background: rgba(0,0,0,0.08); /* Light Divider */
                    margin: 4px 6px;
                }
                [data-theme="dark"] .dropdown-divider { background: rgba(255,255,255,0.08); }

                .dropdown-item {
                    background: transparent;
                    border: none;
                    text-align: left;
                    padding: 6px 12px;
                    border-radius: 5px;
                    font-size: var(--text-footnote);
                    cursor: pointer;
                    color: inherit;
                    transition: background 0.1s;
                }
                .dropdown-item:hover {
                    background: var(--accent-color, #007aff);
                    color: white;
                }
                .dropdown-item.danger:hover {
                    background: #ff3b30;
                }

                .icon-btn {
                    padding: 4px 8px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                }
                
                .badge-dot {
                    position: absolute;
                    top: 6px;
                    right: 6px;
                    width: 6px;
                    height: 6px;
                    background: #ff3b30;
                    border-radius: 50%;
                    box-shadow: 0 0 0 1px white;
                }
                [data-theme="dark"] .badge-dot { box-shadow: 0 0 0 1px #333; }

                /* Responsive */
                @media (max-width: 768px) {
                    .menubar-left .menu-item:not(.app-name) {
                        display: none; /* Hide File, Edit, View, Window, Help */
                    }
                    .clock {
                        display: none; /* Optionally hide clock to save space on very small screens */
                    }
                    .user-profile .user-name {
                        display: none; /* Hide name text, keep avatar */
                    }
                }

            `}</style>
        </header>
    )
}

export default MenuBar
