import { useState, useEffect } from 'react'
import { CELEBRATION_POINTS } from '../App'
import { useAuth } from '../contexts/AuthContext'
import ProfilePicker from '../components/ProfilePicker'

function Admin() {
    const { showToast, user: currentUser } = useAuth()
    const isTechSupport = currentUser?.role === 'TechSupport'
    const [users, setUsers] = useState([])
    const [loading, setLoading] = useState(true)
    const [showModal, setShowModal] = useState(false)
    const [editingUser, setEditingUser] = useState(null)
    const [formData, setFormData] = useState({
        username: '',
        password: '',
        name: '',
        role: 'Coordinator',
        celebration_point: '',
        profile_image: ''
    })

    useEffect(() => {
        loadUsers()
    }, [])

    const loadUsers = async () => {
        setLoading(true)
        try {
            const response = await fetch('/api/admin/users')
            const data = await response.json()
            if (data.success) {
                let userList = data.users || []
                // TechSupport can only manage Facilitator accounts (PRD 2.3)
                if (isTechSupport) {
                    userList = userList.filter(u => u.role === 'Facilitator')
                }
                setUsers(userList)
            }
        } catch (error) {
            showToast('Failed to load users', 'error')
        } finally {
            setLoading(false)
        }
    }

    const handleOpenModal = (user = null) => {
        if (user) {
            setEditingUser(user)
            setFormData({
                username: user.username,
                password: '',
                name: user.name,
                role: user.role,
                celebration_point: user.celebration_point || '',
                profile_image: user.profile_image || ''
            })
        } else {
            setEditingUser(null)
            setFormData({
                username: '',
                password: '',
                name: '',
                role: isTechSupport ? 'Facilitator' : 'Coordinator',
                celebration_point: '',
                profile_image: ''
            })
        }
        setShowModal(true)
    }

    const handleCloseModal = () => {
        setShowModal(false)
        setEditingUser(null)
        setFormData({
            username: '',
            password: '',
            name: '',
            role: 'Coordinator',
            celebration_point: '',
            profile_image: ''
        })
    }

    const handleSubmit = async (e) => {
        e.preventDefault()

        const campusScopedRoles = ['Pastor', 'Coordinator', 'TechSupport', 'Facilitator']
        if (campusScopedRoles.includes(formData.role) && !formData.celebration_point) {
            showToast(`${formData.role} must be assigned a Celebration Point`, 'error')
            return
        }

        try {
            const url = editingUser
                ? `/api/admin/users/${editingUser.id}`
                : '/api/admin/users'

            const method = editingUser ? 'PUT' : 'POST'

            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData)
            })

            const data = await response.json()

            if (data.success) {
                showToast(editingUser ? 'User updated successfully' : 'User created successfully', 'success')
                handleCloseModal()
                loadUsers()
            } else {
                showToast(data.message || 'Operation failed', 'error')
            }
        } catch (error) {
            showToast('Failed to save user', 'error')
        }
    }

    const handleDeactivate = async (userId) => {
        if (!confirm('Are you sure you want to deactivate this user?')) return

        try {
            const response = await fetch(`/api/admin/users/${userId}`, {
                method: 'DELETE'
            })
            const data = await response.json()

            if (data.success) {
                showToast('User deactivated', 'success')
                loadUsers()
            } else {
                showToast(data.message || 'Failed to deactivate user', 'error')
            }
        } catch (error) {
            showToast('Failed to deactivate user', 'error')
        }
    }

    const handleDeletePermanent = async (userId) => {
        if (!confirm('WARNING: IRREVERSIBLE ACTION\n\nAre you sure you want to PERMANENTLY DELETE this user? This cannot be undone.')) return

        try {
            const response = await fetch(`/api/admin/users/${userId}/permanent`, {
                method: 'DELETE'
            })
            const data = await response.json()

            if (data.success) {
                showToast('User permanently deleted', 'success')
                loadUsers()
            } else {
                showToast(data.message || 'Failed to delete user', 'error')
            }
        } catch (error) {
            showToast('Failed to delete user', 'error')
        }
    }

    return (
        <div className="page-container" style={{ padding: '24px', maxWidth: 1200, margin: '0 auto' }}>
            <div className="section-header admin-header" style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24, flexWrap: 'wrap', gap: 12,
                background: 'var(--glass-layer-2)', backdropFilter: 'var(--blur-layer-3)',
                padding: '16px 24px', borderRadius: 20, border: 'var(--border-layer-2)',
                boxShadow: 'var(--shadow-layer-2)'
            }}>
                <h2 style={{ margin: 0, fontSize: 22, color: 'var(--text-primary)' }}>User Management</h2>
                <button
                    className="btn-primary"
                    onClick={() => handleOpenModal()}
                    style={{
                        width: 'auto', padding: '8px 18px', fontSize: 13,
                        boxShadow: 'var(--shadow-layer-3)'
                    }}
                >
                    + Add New User
                </button>
            </div>

            {loading ? (
                <div className="loading-container">
                    <div className="spinner"></div>
                    <p>Loading users...</p>
                </div>
            ) : (
                <div className="admin-grid" style={{
                    display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 16
                }}>
                    {users.map(user => (
                        <div key={user.id} className="glass-card user-card" style={{
                            background: 'var(--glass-layer-1)', backdropFilter: 'var(--blur-layer-2)',
                            border: 'var(--border-layer-1)', borderRadius: 16, padding: 20,
                            display: 'flex', flexDirection: 'column', gap: 16,
                            transition: 'transform 0.2s, box-shadow 0.2s, background 0.2s'
                        }}
                            onMouseEnter={e => {
                                e.currentTarget.style.transform = 'translateY(-4px)'
                                e.currentTarget.style.boxShadow = 'var(--shadow-layer-3)'
                                e.currentTarget.style.background = 'var(--glass-layer-2)'
                            }}
                            onMouseLeave={e => {
                                e.currentTarget.style.transform = 'translateY(0)'
                                e.currentTarget.style.boxShadow = 'none'
                                e.currentTarget.style.background = 'var(--glass-layer-1)'
                            }}
                        >
                            <div className="user-card-header" style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                                <div className="user-avatar-small" style={{
                                    width: 48, height: 48, borderRadius: '50%', fontSize: 20,
                                    background: 'linear-gradient(135deg, var(--glass-layer-3), var(--glass-layer-2))',
                                    border: 'var(--border-layer-2)',
                                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                                    color: 'var(--text-primary)', fontWeight: 600, overflow: 'hidden',
                                    flexShrink: 0
                                }}>
                                    {user.profile_image ? (
                                        <img src={user.profile_image} alt={user.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                    ) : (
                                        user.name.charAt(0)
                                    )}
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div className="user-card-name" style={{ fontSize: 16, fontWeight: 600, color: 'var(--text-primary)' }}>{user.name}</div>
                                    <span className={`user-card-role ${user.role.toLowerCase()}`} style={{
                                        fontSize: 11, padding: '2px 8px', borderRadius: 6,
                                        background: 'var(--glass-layer-3)', color: 'var(--text-secondary)',
                                        border: 'var(--border-layer-1)', display: 'inline-block', marginTop: 4
                                    }}>
                                        {user.role}
                                    </span>
                                </div>
                            </div>

                            <div className="user-card-details" style={{
                                background: 'var(--glass-layer-2)', borderRadius: 10, padding: 12,
                                fontSize: 13, color: 'var(--text-secondary)', border: 'var(--border-layer-1)'
                            }}>
                                <div style={{ marginBottom: 4 }}>Username: <span style={{ color: 'var(--text-primary)' }}>{user.username}</span></div>
                                {user.celebration_point && (
                                    <div style={{ marginBottom: 4 }}>Campus: <span style={{ color: 'var(--text-primary)' }}>{user.celebration_point}</span></div>
                                )}
                                <div>Status: <span style={{ color: user.active ? '#34C759' : '#FF3B30' }}>{user.active ? 'Active' : 'Inactive'}</span></div>
                            </div>

                            <div className="user-card-actions" style={{ display: 'flex', gap: 10, marginTop: 'auto' }}>
                                <button
                                    onClick={() => handleOpenModal(user)}
                                    style={{
                                        flex: 1, padding: '8px', border: 'var(--border-layer-2)',
                                        background: 'var(--glass-layer-2)', color: 'var(--text-primary)',
                                        fontSize: 13, cursor: 'pointer', transition: 'background 0.2s', fontWeight: 500
                                    }}
                                    onMouseEnter={e => e.target.style.background = 'var(--glass-layer-3)'}
                                    onMouseLeave={e => e.target.style.background = 'var(--glass-layer-2)'}
                                >
                                    Edit
                                </button>
                                {user.active && (
                                    <button
                                        onClick={() => handleDeactivate(user.id)}
                                        style={{
                                            flex: 1, padding: '8px', border: '1px solid rgba(255,59,48,0.2)',
                                            background: 'rgba(255,59,48,0.1)', color: '#ff3b30',
                                            fontSize: 13, cursor: 'pointer', transition: 'background 0.2s', fontWeight: 500
                                        }}
                                        onMouseEnter={e => e.target.style.background = 'rgba(255,59,48,0.2)'}
                                        onMouseLeave={e => e.target.style.background = 'rgba(255,59,48,0.1)'}
                                    >
                                        Deactivate
                                    </button>
                                )}
                                {!user.active && !isTechSupport && (
                                    <button
                                        onClick={() => handleDeletePermanent(user.id)}
                                        style={{
                                            flex: 1, padding: '8px', border: '1px solid rgba(255,59,48,0.4)',
                                            background: 'rgba(255,59,48,0.2)', color: '#ff3b30',
                                            fontSize: 13, cursor: 'pointer', transition: 'background 0.2s', fontWeight: 600
                                        }}
                                        onMouseEnter={e => e.target.style.background = 'rgba(255,59,48,0.3)'}
                                        onMouseLeave={e => e.target.style.background = 'rgba(255,59,48,0.2)'}
                                    >
                                        Delete
                                    </button>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            )}
            {/* User Modal - Tahoe Style */}
            {
                showModal && (
                    <div className="modal-overlay" onClick={handleCloseModal} style={{
                        position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10000,
                        backdropFilter: 'blur(5px)'
                    }}>
                        <div
                            className="glass-card modal"
                            onClick={e => e.stopPropagation()}
                            style={{
                                width: '800px', maxWidth: '95%', padding: '0',
                                display: 'flex', flexDirection: 'column', overflow: 'hidden',
                                borderRadius: '20px', border: 'var(--border-layer-2)',
                                background: 'var(--glass-layer-4)', backdropFilter: 'var(--blur-layer-4)',
                                boxShadow: 'var(--shadow-layer-4)'
                            }}
                        >
                            {/* macOS Window Title Bar */}
                            <div style={{
                                height: '44px', background: 'var(--glass-layer-3)', borderBottom: 'var(--border-layer-1)',
                                display: 'flex', alignItems: 'center', padding: '0 16px'
                            }}>
                                <div style={{ display: 'flex', gap: '8px' }}>
                                    <button onClick={handleCloseModal} style={{ width: '12px', height: '12px', borderRadius: '50%', background: '#ff5f56', border: '1px solid #e0443e', cursor: 'pointer' }}></button>
                                    <div style={{ width: '12px', height: '12px', borderRadius: '50%', background: '#ffbd2e', border: '1px solid #dea123' }}></div>
                                    <div style={{ width: '12px', height: '12px', borderRadius: '50%', background: '#27c93f', border: '1px solid #1aab29' }}></div>
                                </div>
                                <div style={{ flex: 1, textAlign: 'center', fontWeight: '500', color: 'var(--text-secondary)', fontSize: '13px' }}>
                                    {editingUser ? 'System Preferences - Edit User' : 'System Preferences - New User'}
                                </div>
                                <div style={{ width: '52px' }}></div> {/* Spacer for centering */}
                            </div>

                            <div style={{ display: 'flex', height: '500px' }}>
                                {/* Left Sidebar - Profile Pic */}
                                <div style={{ width: '280px', background: 'var(--glass-layer-1)', borderRight: 'var(--border-layer-1)', padding: '32px 24px', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                                    <div style={{
                                        width: '140px', height: '140px', borderRadius: '50%',
                                        background: 'var(--glass-layer-2)', marginBottom: '24px',
                                        border: '4px solid var(--border-layer-2)', overflow: 'hidden',
                                        boxShadow: 'var(--shadow-layer-3)',
                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        color: 'var(--text-secondary)'
                                    }}>
                                        {formData.profile_image ? (
                                            <img src={formData.profile_image} alt="Preview" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                        ) : (
                                            <span style={{ fontSize: '48px', color: 'var(--text-secondary)', opacity: 0.5 }}>?</span>
                                        )}
                                    </div>
                                    <div style={{ width: '100%' }}>
                                        <label style={{ display: 'block', fontSize: '12px', color: 'var(--text-secondary)', marginBottom: '12px', textAlign: 'center' }}>Select Avatar</label>
                                        <ProfilePicker
                                            selectedImage={formData.profile_image}
                                            onSelect={(img) => setFormData({ ...formData, profile_image: img })}
                                        />
                                    </div>
                                </div>

                                {/* Main Content - Form */}
                                <div style={{ flex: 1, padding: '32px', overflowY: 'auto' }}>
                                    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
                                        <div className="form-group">
                                            <label className="form-label" style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: 8, display: 'block' }}>Full Name</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={formData.name}
                                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                                required
                                                style={{
                                                    width: '100%', padding: '12px 16px', borderRadius: 10,
                                                    background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
                                                    color: 'var(--text-primary)', fontSize: 14, outline: 'none', boxSizing: 'border-box'
                                                }}
                                                placeholder="Joshua Migadde"
                                            />
                                        </div>

                                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                                            <div className="form-group">
                                                <label className="form-label" style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: 8, display: 'block' }}>Username</label>
                                                <input
                                                    type="text"
                                                    className="form-input"
                                                    value={formData.username}
                                                    onChange={(e) => setFormData({ ...formData, username: e.target.value })}
                                                    required
                                                    disabled={!!editingUser}
                                                    style={{
                                                        width: '100%', padding: '12px 16px', borderRadius: 10,
                                                        background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
                                                        color: 'var(--text-primary)', fontSize: 14, outline: 'none', boxSizing: 'border-box'
                                                    }}
                                                    placeholder="joshua.m"
                                                />
                                            </div>
                                            <div className="form-group">
                                                <label className="form-label" style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: 8, display: 'block' }}>Account Type</label>
                                                <select
                                                    className="form-select"
                                                    value={formData.role}
                                                    onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                                                    style={{
                                                        width: '100%', padding: '12px 16px', borderRadius: 10,
                                                        background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
                                                        color: 'var(--text-primary)', fontSize: 14, outline: 'none', boxSizing: 'border-box',
                                                        appearance: 'none'
                                                    }}
                                                >
                                                    {isTechSupport ? (
                                                        <option value="Facilitator">Facilitator</option>
                                                    ) : (
                                                        <>
                                                            <option value="Coordinator">Coordinator</option>
                                                            <option value="Pastor">Pastor</option>
                                                            <option value="Facilitator">Facilitator</option>
                                                            <option value="TechSupport">Tech Support</option>
                                                            <option value="LeadershipTeam">Leadership Team</option>
                                                            <option value="Admin">Admin</option>
                                                        </>
                                                    )}
                                                </select>
                                            </div>
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label" style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: 8, display: 'block' }}>
                                                Password {editingUser && <span style={{ opacity: 0.5 }}>(leave blank to keep current)</span>}
                                            </label>
                                            <input
                                                type="password"
                                                className="form-input"
                                                value={formData.password}
                                                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                                required={!editingUser}
                                                style={{
                                                    width: '100%', padding: '12px 16px', borderRadius: 10,
                                                    background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
                                                    color: 'var(--text-primary)', fontSize: 14, outline: 'none', boxSizing: 'border-box'
                                                }}
                                                placeholder="••••••••"
                                            />
                                        </div>

                                        {['Pastor', 'Coordinator', 'TechSupport', 'Facilitator'].includes(formData.role) && (
                                            <div className="form-group">
                                                <label className="form-label" style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: 8, display: 'block' }}>Assigned Celebration Point</label>
                                                <select
                                                    className="form-select"
                                                    value={formData.celebration_point}
                                                    onChange={(e) => setFormData({ ...formData, celebration_point: e.target.value })}
                                                    required
                                                    style={{
                                                        width: '100%', padding: '12px 16px', borderRadius: 10,
                                                        background: 'var(--glass-layer-1)', border: 'var(--border-layer-2)',
                                                        color: 'var(--text-primary)', fontSize: 14, outline: 'none', boxSizing: 'border-box',
                                                        appearance: 'none'
                                                    }}
                                                >
                                                    <option value="">Select Celebration Point...</option>
                                                    {CELEBRATION_POINTS.map(cp => (
                                                        <option key={cp} value={cp}>{cp}</option>
                                                    ))}
                                                </select>
                                            </div>
                                        )}

                                        <div style={{ flex: 1 }}></div>

                                        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px', paddingTop: '24px', borderTop: 'var(--border-layer-1)' }}>
                                            <button
                                                type="button"
                                                onClick={handleCloseModal}
                                                style={{
                                                    padding: '10px 20px', borderRadius: 10, cursor: 'pointer',
                                                    border: 'var(--border-layer-2)', background: 'transparent',
                                                    color: 'var(--text-primary)', fontSize: 13, fontWeight: 500
                                                }}
                                            >
                                                Cancel
                                            </button>
                                            <button type="submit" className="btn-primary" style={{ padding: '10px 24px', borderRadius: 10, fontSize: 13, boxShadow: 'var(--shadow-layer-2)' }}>
                                                {editingUser ? 'Save Changes' : 'Create Account'}
                                            </button>
                                        </div>
                                    </form>
                                </div>
                            </div>
                        </div>
                    </div>
                )
            }
        </div >
    )
}

export default Admin
