import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import SettingsModal from '../components/SettingsModal'

const SettingsContext = createContext()

export function useSettings() {
    return useContext(SettingsContext)
}

export function SettingsProvider({ children }) {
    const [isSettingsOpen, setIsSettingsOpen] = useState(false)

    // ── Theme Preference: 'light' | 'dark' | 'auto' ──
    const [themePreference, setThemePreference] = useState(() => {
        return localStorage.getItem('themePreference') || 'dark'
    })

    // ── Focus Mode: 'default' | 'facilitator' | 'coordinator' | 'pastor' ──
    const [focusMode, setFocusMode] = useState(() => {
        return localStorage.getItem('focusMode') || 'default'
    })

    // Apply theme based on preference
    const applyTheme = useCallback((pref) => {
        if (pref === 'auto') {
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches
            document.documentElement.setAttribute('data-theme', prefersDark ? 'dark' : 'light')
        } else {
            document.documentElement.setAttribute('data-theme', pref)
        }
    }, [])

    // Theme change handler
    const changeTheme = useCallback((pref) => {
        setThemePreference(pref)
        localStorage.setItem('themePreference', pref)
        applyTheme(pref)
    }, [applyTheme])

    // Focus mode change handler
    const changeFocusMode = useCallback((mode) => {
        setFocusMode(mode)
        localStorage.setItem('focusMode', mode)
    }, [])

    // Apply theme on mount
    useEffect(() => {
        applyTheme(themePreference)
    }, [themePreference, applyTheme])

    // Listen for system theme changes when in 'auto' mode
    useEffect(() => {
        if (themePreference !== 'auto') return

        const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')
        const handler = (e) => {
            document.documentElement.setAttribute('data-theme', e.matches ? 'dark' : 'light')
        }
        mediaQuery.addEventListener('change', handler)
        return () => mediaQuery.removeEventListener('change', handler)
    }, [themePreference])

    const openSettings = () => setIsSettingsOpen(true)
    const closeSettings = () => setIsSettingsOpen(false)
    const toggleSettings = () => setIsSettingsOpen(prev => !prev)

    const value = {
        isSettingsOpen,
        openSettings,
        closeSettings,
        toggleSettings,
        // Theme
        themePreference,
        changeTheme,
        // Focus Mode
        focusMode,
        changeFocusMode
    }

    return (
        <SettingsContext.Provider value={value}>
            {children}
            {/* Global Settings Modal */}
            <SettingsModal isOpen={isSettingsOpen} onClose={closeSettings} />
        </SettingsContext.Provider>
    )
}
